/* Clear-button slide-in / slide-out animation — shared canonical definition */
@import './BTInputClear.css';

.bt-input__wrapper {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);                                         /* spacing.xs — replaces margin-top on helper */
  font-family: var(--typography-font-family-sans);
}

.bt-input {
  position: relative;
  height: 50px;                    /* Figma: 1px border + 16px pad + 16px content + 16px pad + 1px border = 50px */
  box-sizing: border-box;
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  display: flex;
  align-items: center;
  gap: var(--space-sm);                        /* spacing.sm — replaces individual prefix/suffix margins */
  padding: 0 8px;                  /* spacing.sm */
  font-family: var(--typography-font-family-sans);
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input--multiline {
  height: auto;
  min-height: 100px;
  padding: 8px;
  align-items: flex-start;
}

/* When label is floating: add breathing room at top & bottom so border
   isn't flush against the floating label or the text below it.
   Icons remain vertically centred in the 32px content area (align-items:center). */
.bt-input--label-floating {
  padding-top: 8px;
  padding-bottom: 8px;
}

.bt-input--focused {
  border-color: var(--color-brand-primary);
  /* NO box-shadow — Figma shows only border-color change */
}

.bt-input--error {
  border-color: var(--text-error);
}

.bt-input--disabled {
  background: var(--bg-subtle);
  cursor: not-allowed;
}

.bt-input__prefix,
.bt-input__suffix {
  display: flex;
  align-items: center;
  flex-shrink: 0;
}

.bt-input__icon-btn {
  background: none; border: none; padding: 0; cursor: pointer;
  display: flex; align-items: center;
  color: var(--icon-primary);
}
.bt-input__icon-btn img,
.bt-input__icon-btn svg { width: 16px; height: 16px; }

.bt-input__field {
  flex: 1;
  height: 100%;
  border: none;
  outline: none;
  background: transparent;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);          /* fontSize.sm */
  font-weight: 500;         /* body/regular — Geist Medium */
  line-height: var(--typography-line-height-xs);        /* lineHeight.xs */
  letter-spacing: 0;        /* letterSpacing.normal */
  color: var(--text-primary);
  padding: 0;
  transition: padding-top 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.bt-input__field::placeholder { color: var(--text-secondary); }
.bt-input--disabled .bt-input__field { color: var(--text-disabled); cursor: not-allowed; }

/* When label is floating: push input text below the floating label.
   Container now supplies 8px top padding → field only needs 16px extra.
   Total from border: 1 + 8(container-pad) + 16(field-pad) = 25px ✓  (same cursor y as before) */
.bt-input--with-label.bt-input--label-floating .bt-input__field {
  padding-top: 16px;
}

.bt-input--multiline .bt-input__field {
  resize: vertical;
  min-height: 84px;
  height: auto;
  padding-top: 0;
}

/* Multiline with floating label — label is absolute-positioned, input doesn't need padding-top shift */
.bt-input--multiline.bt-input--with-label.bt-input--label-floating .bt-input__field {
  padding-top: 8px;   /* small top padding for comfort inside textarea, NOT 24px */
}

/* Label */
.bt-input__label {
  position: absolute;
  pointer-events: none;
  inset-inline-start: var(--space-sm);           /* spacing.sm — was 12px */
  top: 50%;
  transform: translateY(-50%);
  font-size: var(--typography-font-size-sm);                  /* fontSize.sm */
  font-weight: 500;                 /* body/regular */
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  color: var(--text-secondary);
  transition: top 150ms cubic-bezier(0.4, 0, 0.2, 1),
              transform 150ms cubic-bezier(0.4, 0, 0.2, 1),
              font-size 150ms cubic-bezier(0.4, 0, 0.2, 1),
              font-weight 150ms cubic-bezier(0.4, 0, 0.2, 1),
              color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.bt-input--with-prefix .bt-input__label { inset-inline-start: var(--space-2xl); }  /* 8px(pad) + 16px(icon) + 8px(gap) = 32px */
.bt-input--label-floating .bt-input__label {
  top: var(--space-sm);           /* spacing.sm */
  transform: none;
  font-size: var(--typography-font-size-xs);    /* fontSize.xs */
  font-weight: 500;   /* body/small — Geist Medium */
}
.bt-input--focused .bt-input__label { color: var(--color-brand-primary); }
.bt-input--error .bt-input__label { color: var(--text-error); }
.bt-input--disabled .bt-input__label { color: var(--text-disabled); }
.bt-input__label-required { color: var(--text-error); margin-inline-start: var(--space-2xs); }

/* Helper text + counter */
.bt-input__helper {
  display: flex;
  gap: var(--space-sm);
  padding: 0 8px;           /* align with field content — spacing.sm */
  font-size: var(--typography-font-size-xs);          /* fontSize.xs */
  font-weight: 500;         /* body/small */
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
}
.bt-input__helper-text { flex: 1; color: var(--text-secondary); }
.bt-input__helper-text--error { color: var(--text-error); }
.bt-input__counter { color: var(--text-secondary); flex-shrink: 0; }

/**
 * BTInput — Material M3 outlined-style text input. Foundation of the btech
 * input family. All composites (BTInputDate, BTInputDropdown, BTInputUnit,
 * etc.) wrap this atom and add overlay/chip behaviour.
 *
 * Sliced from Figma InputField (node 85:2484) + InputWithLabel (node 368:6832).
 *
 * Variant precedence (suffix priority, highest first):
 *   1. focused + value non-empty + not disabled/readOnly + not password → clear ✕
 *   2. type=password + showPasswordToggle → eye/eye-off toggle
 *   3. suffix prop (only when none of 1–2 apply)
 *
 * Error state shows ONLY via border colour + red helper text — no suffix icon.
 * NOTE: `clearable` prop kept for backward-compat but no longer required — the
 * cancel icon appears automatically whenever the field is focused and non-empty.
 *
 * ## Usage:
 * ```tsx
 * <BTInput label="Username" required placeholder="Type your username"
 *          value={val} onChange={setVal} />
 * <BTInput label="Password" type="password" showPasswordToggle
 *          value={pwd} onChange={setPwd} />
 * <BTInput label="Email" type="email" errorText="Invalid email" />
 * ```
 */
import * as React from 'react';
import './BTInput.css';
import type { BTInputProps } from './BTInput.types';
import { BTInputAnimatedLabel } from './internal/BTInputAnimatedLabel';
import eyeIcon from './icons/eye.svg';
import eyeOffIcon from './icons/eye-off.svg';
import cancelIcon from './icons/cancel.svg';

type SuffixKind = 'clear' | 'password' | 'slot' | null;

const cn = (...parts: Array<string | false | null | undefined>): string =>
  parts.filter(Boolean).join(' ');

export const BTInput = React.forwardRef<
  HTMLInputElement | HTMLTextAreaElement,
  BTInputProps
>(function BTInput(
  {
    value,
    placeholder,
    label,
    required = false,
    disabled = false,
    readOnly = false,
    errorText,
    helperText,
    type = 'text',
    showPasswordToggle = false,
    multiline = false,
    rows = 5,
    maxLength,
    showCharCount = false,
    clearable = false,
    id,
    name,
    prefix,
    suffix,
    onChange,
    onFocus,
    onBlur,
    onClear,
    className,
  },
  ref,
) {
  const [isFocused, setIsFocused] = React.useState(false);
  const [passwordVisible, setPasswordVisible] = React.useState(false);

  const hasError = !!errorText;
  const isEmpty = !value;
  const hasPrefix = !!prefix;
  const showFloatingLabel = !!label && (isFocused || !isEmpty);

  const inputType: React.HTMLInputTypeAttribute =
    type === 'password' ? (passwordVisible ? 'text' : 'password') : type;

  // Suffix priority: clear (focused + non-empty, no clearable gate) > password-toggle > slot
  // Error shows only via border + helper text — no suffix icon.
  const suffixKind = React.useMemo<SuffixKind>(() => {
    if (!isEmpty && !disabled && !readOnly && isFocused && type !== 'password') return 'clear';
    if (type === 'password' && showPasswordToggle) return 'password';
    if (suffix) return 'slot';
    return null;
  }, [isEmpty, disabled, readOnly, isFocused, type, showPasswordToggle, suffix]);

  const wrapperClass = cn(
    'bt-input',
    isFocused && 'bt-input--focused',
    hasError && 'bt-input--error',
    disabled && 'bt-input--disabled',
    label && 'bt-input--with-label',
    hasPrefix && 'bt-input--with-prefix',
    showFloatingLabel && 'bt-input--label-floating',
    multiline && 'bt-input--multiline',
    className,
  );

  function handleInput(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) {
    onChange?.(e.target.value);
  }

  function handleFocus(e: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>) {
    setIsFocused(true);
    onFocus?.(e);
  }

  function handleBlur(e: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>) {
    setIsFocused(false);
    onBlur?.(e);
  }

  function handleClear() {
    onChange?.('');
    onClear?.();
  }

  const sharedFieldProps = {
    id,
    name,
    value: value ?? '',
    placeholder: !label || showFloatingLabel ? placeholder : '',
    disabled,
    maxLength,
    className: 'bt-input__field',
    onChange: handleInput,
    onFocus: handleFocus,
    onBlur: handleBlur,
  };

  return (
    <div className="bt-input__wrapper">
      <div className={wrapperClass}>
        {hasPrefix && (
          <span className="bt-input__prefix">{prefix}</span>
        )}

        {label && (
          <BTInputAnimatedLabel label={label} required={required} />
        )}

        {multiline ? (
          <textarea
            {...sharedFieldProps}
            ref={ref as React.ForwardedRef<HTMLTextAreaElement>}
            rows={rows}
            readOnly={readOnly}
          />
        ) : (
          <input
            {...sharedFieldProps}
            ref={ref as React.ForwardedRef<HTMLInputElement>}
            type={inputType}
            readOnly={readOnly}
          />
        )}

        {/* Clear button — direct child of flex row so animation fires on enter/exit.
            Uses onPointerDown.preventDefault() to avoid blur firing before clear. */}
        {suffixKind === 'clear' && (
          <button
            type="button"
            className="bt-input__icon-btn bt-input-clear-enter"
            aria-label="Clear input"
            onPointerDown={(e) => { e.preventDefault(); handleClear(); }}
          >
            <img src={cancelIcon} alt="" />
          </button>
        )}

        {/* Password toggle + suffix slot */}
        {(suffixKind === 'password' || suffixKind === 'slot') && (
          <span className="bt-input__suffix">
            {suffixKind === 'password' && (
              <button
                type="button"
                className="bt-input__icon-btn"
                aria-label={passwordVisible ? 'Hide password' : 'Show password'}
                onClick={() => setPasswordVisible((v) => !v)}
              >
                <img src={passwordVisible ? eyeOffIcon : eyeIcon} alt="" />
              </button>
            )}
            {suffixKind === 'slot' && suffix}
          </span>
        )}
      </div>

      {(errorText || helperText || (showCharCount && maxLength)) && (
        <div className="bt-input__helper">
          <span className={cn('bt-input__helper-text', hasError && 'bt-input__helper-text--error')}>
            {errorText || helperText}
          </span>
          {showCharCount && maxLength && (
            <span className="bt-input__counter">
              {(value ?? '').length}/{maxLength}
            </span>
          )}
        </div>
      )}
    </div>
  );
});

BTInput.displayName = 'BTInput';

export type BTInputType =
  | 'text'
  | 'password'
  | 'email'
  | 'number'
  | 'tel'
  | 'url';

export interface BTInputProps {
  /** Controlled value. Pair with onChange. */
  value?: string;
  placeholder?: string;
  label?: string;
  required?: boolean;
  disabled?: boolean;
  readOnly?: boolean;
  errorText?: string;
  helperText?: string;
  type?: BTInputType;
  showPasswordToggle?: boolean;
  multiline?: boolean;
  rows?: number;
  maxLength?: number;
  showCharCount?: boolean;
  clearable?: boolean;
  id?: string;
  name?: string;
  /** Left content (icon, currency symbol). React.ReactNode equivalent of Vue's prefix slot. */
  prefix?: React.ReactNode;
  /** Right content (custom icon, button) — lowest suffix priority. */
  suffix?: React.ReactNode;
  /** Called with the new string value on every keystroke. */
  onChange?: (value: string) => void;
  onFocus?: (event: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>) => void;
  onBlur?: (event: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>) => void;
  /** Called after the field is cleared via the clear button. */
  onClear?: () => void;
  className?: string;
}

/*
 * BTInputClear — canonical slide-from-right animation for all input clear/cancel buttons.
 *
 * Vue: wrap with <Transition name="bt-input-clear"> — uses enter/leave classes below.
 * React: add class "bt-input-clear-enter" on the button element — uses keyframe below.
 *
 * DO NOT use a CSS class toggle (--visible) approach — always conditionally render
 * so the button is removed from the DOM (and tab order) when not shown.
 */

/* ── Vue Transition hooks ─────────────────────────────────────────────────── */

.bt-input-clear-enter-active,
.bt-input-clear-leave-active {
  transition: opacity 150ms cubic-bezier(0.4, 0, 0.2, 1),
              transform 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-clear-enter-from,
.bt-input-clear-leave-to {
  opacity: 0;
  transform: translateX(6px);
}

.bt-input-clear-enter-to,
.bt-input-clear-leave-from {
  opacity: 1;
  transform: translateX(0);
}

/* ── React mount animation (no leave — element is removed from DOM instantly) */

@keyframes bt-input-clear-in {
  from { opacity: 0; transform: translateX(6px); }
  to   { opacity: 1; transform: translateX(0); }
}

.bt-input-clear-enter {
  animation: bt-input-clear-in 150ms cubic-bezier(0.4, 0, 0.2, 1) both;
}

/* Clear-button slide-in / slide-out animation — shared canonical definition */
@import '../BTInputClear.css';

/*
 * BTInputDate — click-to-open date / date-range picker.
 * Figma node 543-2651.
 *
 * Layout follows BTInput exactly — position:relative on the field div,
 * label is position:absolute inside it. No inner content wrapper.
 *
 * Visual structure (flex-row, height 50px — same as BTInput):
 * ┌── field (position:relative) ──────────────────────────────────┐
 * │  [📅 16px]  │  label (absolute, resting↔floating)  │  value  │ [×?] │
 * └────────────────────────────────────────────────────────────────┘
 */

/* ── Outer wrapper ───────────────────────────────────────────── */
.bt-input-date__wrapper {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  font-family: var(--typography-font-family-sans);
  width: 100%;
}

/* ── Field row ───────────────────────────────────────────────── */
/*
 * position: relative — required so the absolute label is positioned
 * relative to this field div, not a parent. Mirrors BTInput exactly.
 */
.bt-input-date {
  position: relative;
  display: flex;
  align-items: center;
  height: 48px;                  /* Figma Default size: 48px */
  box-sizing: border-box;
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  background: var(--bg-primary);
  padding: 0 8px;
  gap: var(--space-sm);
  cursor: pointer;
  user-select: none;
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

/* When label is floating: add breathing room (mirrors BTInput--label-floating) */
.bt-input-date--label-floating {
  padding-top: 8px;
  padding-bottom: 8px;
}

/* States */
.bt-input-date--open     { border-color: var(--color-brand-primary); }
.bt-input-date--error    { border-color: var(--text-error); }
.bt-input-date--disabled {
  background: var(--bg-subtle);
  cursor: not-allowed;
  pointer-events: none;
}

/* ── Calendar icon ───────────────────────────────────────────── */
.bt-input-date__icon {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  color: var(--text-secondary);
}

.bt-input-date__icon img,
.bt-input-date__icon svg {
  width: 16px;
  height: 16px;
  display: block;
}

.bt-input-date--open     .bt-input-date__icon { color: var(--color-brand-primary); }
.bt-input-date--error    .bt-input-date__icon { color: var(--text-error); }
.bt-input-date--disabled .bt-input-date__icon { color: var(--text-disabled); }

/* ── Floating label ──────────────────────────────────────────── */
/*
 * position: absolute inside the position:relative field div.
 * left: 32px = 8px(pad) + 16px(icon) + 8px(gap) — mirrors BTInput with prefix.
 * Resting: centered vertically. Floating: small at top.
 */
.bt-input-date__label {
  position: absolute;
  pointer-events: none;
  inset-inline-start: var(--space-2xl);
  top: 50%;
  transform: translateY(-50%);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: calc(100% - 56px); /* 32px start + 16px clear + 8px gap */
  transition: top        150ms cubic-bezier(0.4, 0, 0.2, 1),
              transform  150ms cubic-bezier(0.4, 0, 0.2, 1),
              font-size  150ms cubic-bezier(0.4, 0, 0.2, 1),
              color      150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-date--label-floating .bt-input-date__label {
  top: var(--space-sm);
  transform: none;
  font-size: var(--typography-font-size-xs);
}

/* Label color per state */
.bt-input-date--open     .bt-input-date__label { color: var(--color-brand-primary); }
.bt-input-date--error    .bt-input-date__label { color: var(--text-error); }
.bt-input-date--disabled .bt-input-date__label { color: var(--text-disabled); }

.bt-input-date__label-required {
  color: var(--text-error);
  margin-inline-start: var(--space-2xs);
}

/* ── Value / placeholder text ────────────────────────────────── */
/*
 * flex: 1; height: 100% — fills available flex space, same as BTInput__field.
 * When floating: padding-top: 16px pushes text below the floating label.
 *   Container top padding (8px) + value padding-top (16px) = 24px from field top.
 *   Floating label: top 8px + line-height 16px = ends at 24px. Perfect alignment.
 */
.bt-input-date__value {
  flex: 1;
  height: 100%;
  min-width: 0;
  display: flex;
  align-items: center;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  transition: padding-top 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

/* When floating: push text down below the floating label.
   padding-top 14px (not 16) gives 2px breathing room for font descenders at 48px height. */
.bt-input-date--label-floating .bt-input-date__value {
  padding-top: 14px;
  align-items: flex-start;
}

/* Placeholder state (open but no value) */
.bt-input-date__value--placeholder {
  color: var(--text-secondary);
}

.bt-input-date--disabled .bt-input-date__value { color: var(--text-disabled); }

/* ── Clear (×) button ────────────────────────────────────────── */
.bt-input-date__clear {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  width: 16px;
  height: 16px;
  color: var(--icon-primary);
}

.bt-input-date__clear img,
.bt-input-date__clear svg {
  width: 16px;
  height: 16px;
  display: block;
}

/* ── Helper / error text ─────────────────────────────────────── */
.bt-input-date__helper {
  display: flex;
  gap: var(--space-sm);
  padding: 0 8px;
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-input-date__helper-text        { flex: 1; color: var(--text-secondary); }
.bt-input-date__helper-text--error { color: var(--text-error); }

/* ── Small variant (size="small") ───────────────────────────────
 * ~40 px auto height.
 * Empty: py-12px  |  Floating: py-4px
 * Value text: 12 px (instead of 14 px for default).
 * Figma: size=Small in node 543-2651.
 */
.bt-input-date--small {
  height: auto;
  padding-top: 12px;
  padding-bottom: 12px;
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1),
              padding     150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-date--small.bt-input-date--label-floating {
  padding-top: 4px;
  padding-bottom: 4px;
}

/* In small floating state, label hugs the top edge at 4 px */
.bt-input-date--small.bt-input-date--label-floating .bt-input-date__label {
  top: var(--space-xs);
}

/* Value: auto height (no 100% — container has no fixed height in small) */
.bt-input-date--small .bt-input-date__value {
  height: auto;
  font-size: var(--typography-font-size-xs);
}

/* Push value text below floating label */
.bt-input-date--small.bt-input-date--label-floating .bt-input-date__value {
  padding-top: 16px;
  align-items: flex-start;
}

/* ── Calendar panel (teleported to body) ─────────────────────── */
.bt-input-date__panel {
  position: fixed;
  z-index: 1000;
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-md);
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.08), 0 1px 4px rgba(0, 0, 0, 0.04);
  box-sizing: border-box;
  overflow: auto;
  max-height: calc(100vh - 32px);
  /* Hidden until JS positions it */
  opacity: 0;
}

.bt-input-date__panel--visible {
  animation: bt-input-date-panel-in 150ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

@keyframes bt-input-date-panel-in {
  from { opacity: 0; transform: scale(0.97); }
  to   { opacity: 1; transform: scale(1); }
}

/**
 * BTInputDate — click-to-open date / date-range picker (React).
 * Figma node 543-2651. Mirrors BTInputDate.vue one-to-one.
 *
 * Usage — single:
 * ```tsx
 * <BTInputDate label="Date" value={date} onChange={setDate} />
 * ```
 * Usage — range:
 * ```tsx
 * <BTInputDate mode="range" label="Period"
 *   rangeValue={range} onRangeValueChange={setRange} />
 * ```
 */
import * as React from 'react';
import { createPortal } from 'react-dom';
import './BTInputDate.css';
import type { BTInputDateHandle, BTInputDateProps } from './BTInputDate.types';
import { BTCalendar } from '../../calendar/index';
import { BTInputAnimatedLabel } from '../internal/BTInputAnimatedLabel';
import { positionBelow } from '../internal/positionFloating';
import calendarIcon from './icons/calendar.svg';
import cancelIcon   from './icons/cancel.svg';

const cn = (...parts: Array<string | false | null | undefined>): string =>
  parts.filter(Boolean).join(' ');

const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];

function fmt(date: Date): string {
  return `${String(date.getDate()).padStart(2,'0')} ${MONTHS[date.getMonth()]} ${date.getFullYear()}`;
}

export const BTInputDate = React.forwardRef<BTInputDateHandle, BTInputDateProps>(
  function BTInputDate(
    {
      mode = 'single',
      size = 'default',
      value,
      rangeValue,
      label,
      required = false,
      disabled = false,
      readOnly = false,
      errorText,
      helperText,
      id,
      minDate,
      maxDate,
      locale,
      showFooter = true,
      showPreset = false,
      onChange,
      onRangeValueChange,
      onClear,
      validator,
      rangeValidator,
      className,
    },
    ref,
  ) {
    const uid = React.useId();
    const fieldId = id ?? `bt-input-date-${uid}`;

    const [isOpen, setIsOpen] = React.useState(false);
    const [errorInternal, setErrorInternal] = React.useState<string | null>(null);
    const [pendingValue, setPendingValue] = React.useState<Date | null>(null);
    const [pendingRange, setPendingRange] = React.useState<[Date, Date] | null>(null);

    const fieldRef = React.useRef<HTMLDivElement>(null);
    const panelRef = React.useRef<HTMLDivElement>(null);

    const activeError = errorText ?? errorInternal ?? null;
    const hasError    = !!activeError;
    const hasValue    = mode === 'range' ? !!(rangeValue?.[0]) : !!value;
    const labelFloating  = isOpen || hasValue;
    const showClear      = isOpen && hasValue && !disabled && !readOnly;
    const showPlaceholder = isOpen && !hasValue;
    const placeholder    = mode === 'range' ? 'DD MMM YYYY – DD MMM YYYY' : 'DD MMM YYYY';

    const displayValue = React.useMemo(() => {
      if (mode === 'range') {
        const r = rangeValue;
        if (!r) return '';
        return `${fmt(r[0])} – ${fmt(r[1])}`;
      }
      return value ? fmt(value) : '';
    }, [mode, value, rangeValue]);

    // Position panel below (or above if no room) the field
    function positionPanel() {
      const f = fieldRef.current;
      const p = panelRef.current;
      if (!f || !p) return;
      // Smart-flip: prefers below, flips above when viewport space is tight
      positionBelow(f, p, { gap: 4, margin: 8 });
      p.classList.add('bt-input-date__panel--visible');
    }

    function openPanel() {
      if (disabled || readOnly || isOpen) return;
      setPendingValue(value ?? null);
      setPendingRange(rangeValue ?? null);
      setIsOpen(true);
    }

    function closePanel() {
      setIsOpen(false);
    }

    function handleClear(e: React.MouseEvent) {
      e.stopPropagation();
      if (mode === 'range') onRangeValueChange?.(null);
      else onChange?.(null);
      onClear?.();
    }

    function handleApply(val: Date | [Date, Date] | null) {
      if (mode === 'range') onRangeValueChange?.(Array.isArray(val) ? val as [Date, Date] : null);
      else onChange?.(val instanceof Date ? val : null);
      setErrorInternal(null);
      closePanel();
    }

    function handleCalendarValue(val: Date | null) {
      setPendingValue(val);
      if (!showFooter) {
        onChange?.(val);
        setErrorInternal(null);
        closePanel();
      }
    }

    function handleCalendarRange(val: [Date, Date] | null) {
      setPendingRange(val);
      if (!showFooter && val) {
        onRangeValueChange?.(val);
        setErrorInternal(null);
        closePanel();
      }
    }

    function handleCancel() {
      closePanel();
    }

    // Outside click + Escape key
    React.useEffect(() => {
      if (!isOpen) return;
      function onDown(e: MouseEvent) {
        if (
          fieldRef.current?.contains(e.target as Node) ||
          panelRef.current?.contains(e.target as Node)
        ) return;
        closePanel();
      }
      function onKeyDown(e: KeyboardEvent) {
        if (e.key === 'Escape') closePanel();
      }
      document.addEventListener('mousedown', onDown);
      document.addEventListener('keydown', onKeyDown);
      return () => {
        document.removeEventListener('mousedown', onDown);
        document.removeEventListener('keydown', onKeyDown);
      };
    }, [isOpen]);

    // Reposition on open
    React.useEffect(() => {
      if (isOpen) positionPanel();
    }, [isOpen]);

    // Reposition on scroll / resize while open
    React.useEffect(() => {
      if (!isOpen) return;
      function reposition() { positionPanel(); }
      document.addEventListener('scroll', reposition, true);
      window.addEventListener('resize', reposition);
      return () => {
        document.removeEventListener('scroll', reposition, true);
        window.removeEventListener('resize', reposition);
      };
    }, [isOpen]);

    // Expose validate()
    React.useImperativeHandle(ref, () => ({
      validate() {
        if (mode === 'range') {
          if (!rangeValidator) return true;
          const r = rangeValidator(rangeValue ?? null);
          setErrorInternal(r ?? null);
          return r === null;
        }
        if (!validator) return true;
        const r = validator(value ?? null);
        setErrorInternal(r ?? null);
        return r === null;
      },
    }), [mode, value, rangeValue, validator, rangeValidator]);

    const fieldClass = cn(
      'bt-input-date',
      isOpen       && 'bt-input-date--open',
      hasError     && 'bt-input-date--error',
      disabled     && 'bt-input-date--disabled',
      labelFloating && 'bt-input-date--label-floating',
      size === 'small' && 'bt-input-date--small',
      className,
    );

    return (
      <>
        <div className="bt-input-date__wrapper">
          <div
            ref={fieldRef}
            id={fieldId}
            className={fieldClass}
            role="button"
            tabIndex={disabled || readOnly ? -1 : 0}
            aria-haspopup="dialog"
            aria-expanded={isOpen}
            onClick={openPanel}
            onKeyDown={e => { if (e.key === 'Enter' || e.key === ' ') openPanel(); }}
          >
            {/* Calendar icon */}
            <span className={cn('bt-input-date__icon', isOpen && 'bt-input-date__icon--open')}>
              <img src={calendarIcon} alt="" width={16} height={16} />
            </span>

            {/* Floating label */}
            {label && (
              <BTInputAnimatedLabel
                label={label}
                required={required}
                className="bt-input-date__label"
                requiredClassName="bt-input-date__label-required"
              />
            )}

            {/* Value / placeholder */}
            <span className={cn('bt-input-date__value', labelFloating && 'bt-input-date__value--floating')}>
              {showPlaceholder
                ? <span className="bt-input-date__placeholder">{placeholder}</span>
                : hasValue
                  ? displayValue
                  : null}
            </span>

            {/* Clear button */}
            {showClear && (
              <button
                type="button"
                className="bt-input-date__clear"
                aria-label="Clear date"
                onMouseDown={e => { e.preventDefault(); e.stopPropagation(); }}
                onClick={handleClear}
              >
                <img src={cancelIcon} alt="" width={16} height={16} />
              </button>
            )}
          </div>

          {/* Helper / error text */}
          {(activeError || helperText) && (
            <div className="bt-input__helper">
              <span className={cn('bt-input__helper-text', hasError && 'bt-input__helper-text--error')}>
                {activeError || helperText}
              </span>
            </div>
          )}
        </div>

        {/* Calendar panel — teleported to body (mirrors Vue's <Teleport to="body">).
            Rendering at body keeps the panel out of the field's DOM subtree so that
            mounting/unmounting the panel does NOT interfere with the CSS padding
            transition on the field (small-size height animation). */}
        {isOpen && createPortal(
          <div ref={panelRef} className="bt-input-date__panel" role="dialog" aria-modal="true">
            <BTCalendar
              mode={mode}
              value={pendingValue}
              rangeValue={pendingRange}
              onValueChange={handleCalendarValue}
              onRangeValueChange={handleCalendarRange}
              minDate={minDate}
              maxDate={maxDate}
              locale={locale}
              showFooter={showFooter}
              showPreset={showPreset}
              onApply={handleApply}
              onCancel={handleCancel}
            />
          </div>,
          document.body,
        )}
      </>
    );
  },
);

BTInputDate.displayName = 'BTInputDate';

/**
 * BTInputDate — tap-to-open date/range picker (React).
 * Figma node 543-2651.
 */
export type BTInputDateMode = 'single' | 'range';
export type BTInputDateSize = 'default' | 'small';

export interface BTInputDateProps {
  mode?: BTInputDateMode;
  size?: BTInputDateSize;
  /** Single-mode value (controlled). */
  value?: Date | null;
  /** Range-mode value (controlled). */
  rangeValue?: [Date, Date] | null;
  label?: string;
  required?: boolean;
  disabled?: boolean;
  readOnly?: boolean;
  errorText?: string;
  helperText?: string;
  id?: string;
  minDate?: Date;
  maxDate?: Date;
  locale?: string;
  /** Show Apply/Cancel footer. Default: true. */
  showFooter?: boolean;
  /** Show built-in preset chips. Default: false. */
  showPreset?: boolean;
  onChange?: (value: Date | null) => void;
  onRangeValueChange?: (value: [Date, Date] | null) => void;
  onClear?: () => void;
  validator?: (value: Date | null) => string | null;
  rangeValidator?: (value: [Date, Date] | null) => string | null;
  className?: string;
}

export interface BTInputDateHandle {
  validate: () => boolean;
}

/* Clear-button slide-in / slide-out animation — shared canonical definition */
@import '../BTInputClear.css';

/*
 * BTInputDropdown — click-to-open dropdown field with floating panel.
 * Figma node 555-3041.
 *
 * Layout follows BTInput exactly — position:relative on the field div,
 * label is position:absolute inside it. No inner content wrapper.
 *
 * Visual structure (flex-row, height 48px — same as BTInputDate):
 * ┌── field (position:relative) ──────────────────────────────────┐
 * │  label (absolute, resting↔floating)  │  value  │  [×?]  │  [↓]  │
 * └────────────────────────────────────────────────────────────────┘
 */

/* ── Outer wrapper ───────────────────────────────────────────── */
.bt-input-dropdown__wrapper {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  font-family: var(--typography-font-family-sans);
  width: 100%;
}

/* ── Field row ───────────────────────────────────────────────── */
/*
 * position: relative — required so the absolute label is positioned
 * relative to this field div, not a parent. Mirrors BTInput exactly.
 */
.bt-input-dropdown {
  position: relative;
  display: flex;
  align-items: center;
  height: 48px;                  /* Figma Default size: 48px */
  box-sizing: border-box;
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  background: var(--bg-primary);
  padding: 0 8px;
  gap: var(--space-sm);
  cursor: pointer;
  user-select: none;
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

/* When label is floating: add breathing room (mirrors BTInput--label-floating) */
.bt-input-dropdown--label-floating {
  padding-top: 8px;
  padding-bottom: 8px;
}

/* States */
.bt-input-dropdown--open     { border-color: var(--color-brand-primary); }
.bt-input-dropdown--error    { border-color: var(--text-error); }
.bt-input-dropdown--disabled {
  background: var(--bg-subtle);
  cursor: not-allowed;
  pointer-events: none;
}

/* ── Floating label ──────────────────────────────────────────── */
/*
 * position: absolute inside the position:relative field div.
 * left: 8px — no icon prefix, aligns to field padding.
 * Resting: centered vertically. Floating: small at top.
 */
.bt-input-dropdown__label {
  position: absolute;
  pointer-events: none;
  inset-inline-start: var(--space-sm);
  top: 50%;
  transform: translateY(-50%);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: calc(100% - 48px); /* 8px start + 16px chevron + 8px clear + gap */
  transition: top        150ms cubic-bezier(0.4, 0, 0.2, 1),
              transform  150ms cubic-bezier(0.4, 0, 0.2, 1),
              font-size  150ms cubic-bezier(0.4, 0, 0.2, 1),
              color      150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-dropdown--label-floating .bt-input-dropdown__label {
  top: var(--space-sm);
  transform: none;
  font-size: var(--typography-font-size-xs);
}

/* Label color per state */
.bt-input-dropdown--open     .bt-input-dropdown__label { color: var(--color-brand-primary); }
.bt-input-dropdown--error    .bt-input-dropdown__label { color: var(--text-error); }
.bt-input-dropdown--disabled .bt-input-dropdown__label { color: var(--text-disabled); }

.bt-input-dropdown__label-required {
  color: var(--text-error);
  margin-inline-start: var(--space-2xs);
}

/* ── Value / placeholder text ────────────────────────────────── */
/*
 * flex: 1; height: 100% — fills available flex space, same as BTInput__field.
 * When floating: padding-top: 16px pushes text below the floating label.
 *   Container top padding (8px) + value padding-top (16px) = 24px from field top.
 *   Floating label: top 8px + line-height 16px = ends at 24px. Perfect alignment.
 */
.bt-input-dropdown__value {
  flex: 1;
  height: 100%;
  min-width: 0;
  display: flex;
  align-items: center;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  transition: padding-top 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

/* When floating: push text down below the floating label.
   padding-top 14px (not 16) gives 2px breathing room for font descenders at 48px height. */
.bt-input-dropdown--label-floating .bt-input-dropdown__value {
  padding-top: 14px;
  align-items: flex-start;
}

/* Placeholder state (open but no value) */
.bt-input-dropdown__value--placeholder {
  color: var(--text-secondary);
}

.bt-input-dropdown--disabled .bt-input-dropdown__value { color: var(--text-disabled); }

/* ── Clear (×) button ────────────────────────────────────────── */
.bt-input-dropdown__clear {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  width: 16px;
  height: 16px;
  color: var(--icon-primary);
}

.bt-input-dropdown__clear img,
.bt-input-dropdown__clear svg {
  width: 16px;
  height: 16px;
  display: block;
}

/* ── Chevron ──────────────────────────────────────────────────── */
.bt-input-dropdown__chevron {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  color: var(--text-secondary);
  transition: transform 150ms cubic-bezier(0.4, 0, 0.2, 1),
              color     150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-dropdown__chevron img,
.bt-input-dropdown__chevron svg {
  width: 16px;
  height: 16px;
  display: block;
}

.bt-input-dropdown--open .bt-input-dropdown__chevron {
  transform: rotate(180deg);
  color: var(--color-brand-primary);
}
.bt-input-dropdown--error    .bt-input-dropdown__chevron { color: var(--text-error); }
.bt-input-dropdown--disabled .bt-input-dropdown__chevron { color: var(--text-disabled); }

/* ── Helper / error text ─────────────────────────────────────── */
.bt-input-dropdown__helper {
  display: flex;
  gap: var(--space-sm);
  padding: 0 8px;
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-input-dropdown__helper-text        { flex: 1; color: var(--text-secondary); }
.bt-input-dropdown__helper-text--error { color: var(--text-error); }

/* ── Small variant (size="small") ───────────────────────────────
 * ~40 px auto height.
 * Empty: py-12px  |  Floating: py-4px
 * Value text: 12 px (instead of 14 px for default).
 * Figma: size=Small in node 555-3041.
 */
.bt-input-dropdown--small {
  height: auto;
  padding-top: 12px;
  padding-bottom: 12px;
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1),
              padding     150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-dropdown--small.bt-input-dropdown--label-floating {
  padding-top: 4px;
  padding-bottom: 4px;
}

/* In small floating state, label hugs the top edge at 4 px */
.bt-input-dropdown--small.bt-input-dropdown--label-floating .bt-input-dropdown__label {
  top: var(--space-xs);
}

/* Value: auto height (no 100% — container has no fixed height in small) */
.bt-input-dropdown--small .bt-input-dropdown__value {
  height: auto;
  font-size: var(--typography-font-size-xs);
}

/* Push value text below floating label */
.bt-input-dropdown--small.bt-input-dropdown--label-floating .bt-input-dropdown__value {
  padding-top: 16px;
  align-items: flex-start;
}

/* ── Dropdown panel (teleported to body) ─────────────────────── */
.bt-input-dropdown__panel {
  position: fixed;
  z-index: 1000;
  /* width set via JS to match trigger width exactly */
  box-sizing: border-box;
  overflow: hidden;
  opacity: 0;
  pointer-events: none;
  transition: opacity 120ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-dropdown__panel--visible {
  opacity: 1;
  pointer-events: auto;
}

/**
 * BTInputDropdown — Input-family select field with floating BTDropdownList panel (React).
 * Figma node 555-3041. Mirrors BTInputDropdown.vue one-to-one.
 *
 * Usage — basic:
 * ```tsx
 * <BTInputDropdown label="City" items={cities} value={city} onChange={setCity} />
 * ```
 * Usage — with search:
 * ```tsx
 * <BTInputDropdown label="Country" items={countries} value={country}
 *                  onChange={setCountry} hasSearch />
 * ```
 */
import * as React from 'react';
import './BTInputDropdown.css';
import type { BTInputDropdownProps } from './BTInputDropdown.types';
import { BTDropdownList } from '../../dropdown-list/index';
import { BTInputAnimatedLabel } from '../internal/BTInputAnimatedLabel';
import expandMoreIcon from './icons/expand_more.svg';
import cancelIcon     from './icons/cancel.svg';

const cn = (...parts: Array<string | false | null | undefined>): string =>
  parts.filter(Boolean).join(' ');

export function BTInputDropdown<T = string>({
  value,
  label,
  items,
  hasSearch = false,
  size = 'default',
  disabled = false,
  readOnly = false,
  required = false,
  errorText,
  helperText,
  id,
  emptyLabel = 'No result found.',
  getLabel,
  onChange,
  onClear,
  className,
}: BTInputDropdownProps<T>) {
  const uid     = React.useId();
  const fieldId = id ?? `bt-input-dropdown-${uid}`;

  const [isOpen,      setIsOpen]      = React.useState(false);
  const [searchQuery, setSearchQuery] = React.useState('');

  const fieldRef = React.useRef<HTMLDivElement>(null);
  const panelRef = React.useRef<HTMLDivElement>(null);

  // ── Derived ─────────────────────────────────────────────────────
  const hasError    = !!errorText;
  const hasValue    = value != null;
  // Float label only when a value is selected — not on open-with-no-value.
  // A dropdown has no typed text to show while the panel is open, so there's
  // no UX reason to float the label when empty (mirrors Vue spec: node 555-3041).
  const labelFloating = hasValue;
  // showClear: only while panel is open AND value is set
  const showClear = isOpen && hasValue && !disabled && !readOnly;

  // ── Selected item & display string ──────────────────────────────
  const selectedItem = React.useMemo(
    () => items.find(item => item.value === value),
    [items, value],
  );

  const displayStr = React.useMemo<string>(() => {
    if (!selectedItem) return '';
    if (getLabel) return getLabel(selectedItem);
    return selectedItem.label ?? '';
  }, [selectedItem, getLabel]);

  // ── Internal search filtering ────────────────────────────────────
  const filteredItems = React.useMemo(() => {
    const base = hasSearch && searchQuery
      ? items.filter(item =>
          (item.label ?? '').toLowerCase().includes(searchQuery.toLowerCase()),
        )
      : items;
    // Mark selected item so BTDropdownList renders checked background
    return base.map(item => ({ ...item, checked: item.value === value }));
  }, [items, hasSearch, searchQuery, value]);

  // ── Panel positioning ────────────────────────────────────────────
  function positionPanel() {
    const trigger = fieldRef.current;
    const panel   = panelRef.current;
    if (!trigger || !panel) return;
    const rect = trigger.getBoundingClientRect();
    // Panel is position:fixed — use viewport coords directly (no scrollX/Y)
    const vw = window.innerWidth;
    const vh = window.innerHeight;
    const pRect = panel.getBoundingClientRect();
    const gap    = 4;
    const margin = 8;

    // Vertical: prefer below, flip above when there's not enough space
    const spaceBelow = vh - rect.bottom - gap;
    const spaceAbove = rect.top - gap;
    const goAbove    = spaceBelow < pRect.height && spaceAbove >= pRect.height;
    const top = goAbove
      ? rect.top  - pRect.height - gap
      : rect.bottom + gap;

    // Horizontal: align to trigger left, clamp to viewport
    let left = rect.left;
    if (left + rect.width > vw - margin) left = vw - margin - rect.width;
    if (left < margin) left = margin;

    panel.style.top   = `${Math.round(top)}px`;
    panel.style.left  = `${Math.round(left)}px`;
    panel.style.width = `${rect.width}px`;
    panel.classList.add('bt-input-dropdown__panel--visible');
  }

  // ── Open / close ─────────────────────────────────────────────────
  function openPanel() {
    if (disabled || readOnly || isOpen) return;
    setSearchQuery('');
    setIsOpen(true);
  }

  function closePanel() {
    setIsOpen(false);
    setSearchQuery('');
  }

  function togglePanel() {
    isOpen ? closePanel() : openPanel();
  }

  // ── Selection ─────────────────────────────────────────────────────
  function handleSelect(val: T) {
    onChange?.(val);
    closePanel();
  }

  // ── Clear ─────────────────────────────────────────────────────────
  function handleClear(e: React.MouseEvent) {
    e.stopPropagation();
    onChange?.(null);
    onClear?.();
    closePanel();
  }

  // ── Keyboard ───────────────────────────────────────────────────────
  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key === 'Escape') {
      if (isOpen) { e.preventDefault(); closePanel(); }
      return;
    }
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      togglePanel();
    }
  }

  // ── Outside click ─────────────────────────────────────────────────
  React.useEffect(() => {
    if (!isOpen) return;
    function onDocumentClick(e: MouseEvent) {
      if (
        fieldRef.current?.contains(e.target as Node) ||
        panelRef.current?.contains(e.target as Node)
      ) return;
      closePanel();
    }
    // Defer by one frame so the opening click doesn't immediately close
    const rafId = requestAnimationFrame(() => {
      document.addEventListener('click', onDocumentClick);
    });
    return () => {
      cancelAnimationFrame(rafId);
      document.removeEventListener('click', onDocumentClick);
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isOpen]);

  // ── Escape key while open ─────────────────────────────────────────
  React.useEffect(() => {
    if (!isOpen) return;
    function onKeyDown(e: KeyboardEvent) {
      if (e.key === 'Escape') closePanel();
    }
    document.addEventListener('keydown', onKeyDown);
    return () => document.removeEventListener('keydown', onKeyDown);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isOpen]);

  // ── Position panel on open ────────────────────────────────────────
  React.useEffect(() => {
    if (isOpen) positionPanel();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isOpen]);

  // ── Scroll / resize repositioning while open ──────────────────────
  React.useEffect(() => {
    if (!isOpen) return;
    let rafId = 0;
    function onScrollOrResize() {
      cancelAnimationFrame(rafId);
      rafId = requestAnimationFrame(positionPanel);
    }
    // capture:true catches scroll on any ancestor container (modal, drawer, etc.)
    window.addEventListener('scroll', onScrollOrResize, { capture: true, passive: true });
    window.addEventListener('resize', onScrollOrResize, { passive: true });
    return () => {
      window.removeEventListener('scroll', onScrollOrResize, { capture: true });
      window.removeEventListener('resize', onScrollOrResize);
      cancelAnimationFrame(rafId);
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isOpen]);

  // ── CSS classes ───────────────────────────────────────────────────
  const fieldClass = cn(
    'bt-input-dropdown',
    isOpen         && 'bt-input-dropdown--open',
    hasError       && 'bt-input-dropdown--error',
    disabled       && 'bt-input-dropdown--disabled',
    labelFloating  && 'bt-input-dropdown--label-floating',
    size === 'small' && 'bt-input-dropdown--small',
    className,
  );

  return (
    <div className="bt-input-dropdown__wrapper">
      {/* Field trigger */}
      <div
        ref={fieldRef}
        id={fieldId}
        className={fieldClass}
        role="combobox"
        aria-expanded={isOpen}
        aria-haspopup="listbox"
        aria-required={required || undefined}
        aria-disabled={disabled || undefined}
        aria-invalid={hasError || undefined}
        tabIndex={disabled ? -1 : 0}
        onClick={togglePanel}
        onKeyDown={handleKeyDown}
      >
        {/* Floating label */}
        {label && (
          <BTInputAnimatedLabel
            label={label}
            required={required}
            className="bt-input-dropdown__label"
            requiredClassName="bt-input-dropdown__label-required"
          />
        )}

        {/* Selected value text */}
        <span className="bt-input-dropdown__value">
          {displayStr}
        </span>

        {/* Clear (×) button — only when open and has value */}
        {showClear && (
          <button
            type="button"
            className="bt-input-dropdown__clear"
            aria-label="Clear selection"
            onMouseDown={e => { e.preventDefault(); e.stopPropagation(); }}
            onClick={handleClear}
          >
            <img src={cancelIcon} alt="" width={16} height={16} />
          </button>
        )}

        {/* Chevron — rotates 180° via CSS when --open; hidden when clear button shown */}
        {!showClear && (
          <span className="bt-input-dropdown__chevron" aria-hidden="true">
            <img src={expandMoreIcon} alt="" width={16} height={16} />
          </span>
        )}
      </div>

      {/* Helper / error text */}
      {(errorText || helperText) && (
        <div className="bt-input-dropdown__helper">
          <span
            className={cn(
              'bt-input-dropdown__helper-text',
              hasError && 'bt-input-dropdown__helper-text--error',
            )}
          >
            {errorText || helperText}
          </span>
        </div>
      )}

      {/* Floating panel — rendered in fixed position (teleported equivalent) */}
      {isOpen && (
        <div
          ref={panelRef}
          className="bt-input-dropdown__panel"
          role="listbox"
          aria-label={label}
        >
          <BTDropdownList
            items={filteredItems}
            searchable={hasSearch}
            searchQuery={searchQuery}
            onSearchChange={setSearchQuery}
            emptyLabel={emptyLabel}
            onSelect={handleSelect}
          />
        </div>
      )}
    </div>
  );
}

BTInputDropdown.displayName = 'BTInputDropdown';

/**
 * BTInputDropdown — input-family select (React).
 *
 * Figma node 555-3041.
 */
import type { BTDropdownItem } from '../../dropdown-list/BTDropdownList.types';

export type BTInputDropdownSize = 'default' | 'small';

export interface BTInputDropdownProps<T = string> {
  /** Currently selected value — must match one of items[n].value */
  value?: T | null;
  /** Floating label text */
  label?: string;
  /** Items to display in the panel */
  items: BTDropdownItem<T>[];
  /**
   * Show a search input at the top of the panel.
   * Filtering is done internally — parent does NOT need to filter items.
   * @default false
   */
  hasSearch?: boolean;
  /**
   * Field height variant.
   * - 'default' → 48px height
   * - 'small'   → auto height, smaller padding
   * @default 'default'
   */
  size?: BTInputDropdownSize;
  /** @default false */
  disabled?: boolean;
  /** @default false */
  readOnly?: boolean;
  /** @default false */
  required?: boolean;
  /** External error message */
  errorText?: string;
  helperText?: string;
  /** Used for label `for` / aria — auto-generated if omitted */
  id?: string;
  /**
   * Text shown in the empty state (no items or no search match).
   * @default 'No result found.'
   */
  emptyLabel?: string;
  /**
   * Convert a BTDropdownItem to a display string shown in the field.
   * Defaults to `item.label ?? ''`.
   */
  getLabel?: (item: BTDropdownItem<T>) => string;
  onChange?: (value: T | null) => void;
  onClear?: () => void;
  className?: string;
}

/* Clear-button slide-in / slide-out animation — shared canonical definition */
@import '../BTInputClear.css';

/*
 * BTInputFieldUnit — split input: unit dropdown (left) + text field (right).
 * Each panel owns its own independent border.
 * Left border activates when the unit dropdown opens.
 * Right border activates when the text field is focused.
 *
 * Shared by Vue (BTInputFieldUnit.vue) and React (BTInputFieldUnit.tsx).
 * Figma node 702-3937.
 */

.bt-input-field-unit__wrapper {
  display: flex;
  flex-direction: column;
  font-family: var(--typography-font-family-sans);
}

/* Flex row — no border here, each panel has its own */
.bt-input-field-unit__row {
  display: flex;
  align-items: stretch;
  min-height: 48px;
}

/* ── Left panel ─────────────────────────────────────────────────────── */
.bt-input-field-unit__left {
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 0 12px;
  width: max-content;
  min-width: 72px;
  flex-shrink: 0;
  cursor: pointer;
  position: relative;
  user-select: none;
  border: 1px solid var(--border-primary);
  border-inline-end: none;
  border-radius: var(--radius-sm) 0 0 var(--radius-sm);
  background: var(--bg-primary);
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.bt-input-field-unit__left--active   { border-color: var(--color-brand-primary); }
.bt-input-field-unit__left--error    { border-color: var(--text-error); }
.bt-input-field-unit__left--disabled { background: var(--bg-subtle); cursor: not-allowed; }

/* ── Divider ────────────────────────────────────────────────────────── */
.bt-input-field-unit__divider {
  width: 1px;
  flex-shrink: 0;
  align-self: stretch;
  background: var(--border-primary);
  transition: background 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.bt-input-field-unit__divider--active { background: var(--color-brand-primary); }
.bt-input-field-unit__divider--error  { background: var(--text-error); }

/* ── Right panel ────────────────────────────────────────────────────── */
.bt-input-field-unit__right {
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 8px 12px;
  position: relative;
  min-width: 0;
  border: 1px solid var(--border-primary);
  border-inline-start: none;
  border-radius: 0 var(--radius-sm) var(--radius-sm) 0;
  background: var(--bg-primary);
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.bt-input-field-unit__right--active   { border-color: var(--color-brand-primary); }
.bt-input-field-unit__right--error    { border-color: var(--text-error); }
.bt-input-field-unit__right--disabled { background: var(--bg-subtle); }

.bt-input-field-unit__right-inner {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
}

/* ── Unit label (top of left panel) ────────────────────────────────── */
.bt-input-field-unit__unit-label {
  font-size: var(--typography-font-size-2xs);
  font-weight: 600;
  line-height: 1;
  color: var(--text-secondary);
  margin-bottom: 2px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  transition: color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.bt-input-field-unit__left--active   .bt-input-field-unit__unit-label { color: var(--color-brand-primary); }
.bt-input-field-unit__left--error    .bt-input-field-unit__unit-label { color: var(--text-error); }
.bt-input-field-unit__left--disabled .bt-input-field-unit__unit-label { color: var(--text-disabled); }

/* ── Unit value row ─────────────────────────────────────────────────── */
.bt-input-field-unit__unit-row {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
}
.bt-input-field-unit__unit-value {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-primary);
  white-space: nowrap;
}
.bt-input-field-unit__left--disabled .bt-input-field-unit__unit-value { color: var(--text-disabled); }

.bt-input-field-unit__unit-chevron {
  display: flex;
  align-items: center;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  color: var(--text-secondary);
  flex-shrink: 0;
}
.bt-input-field-unit__unit-chevron:disabled { color: var(--text-disabled); cursor: not-allowed; }
.bt-input-field-unit__unit-chevron svg {
  width: 16px;
  height: 16px;
  fill: currentColor;
  transition: transform 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.bt-input-field-unit__unit-chevron--open svg { transform: rotate(180deg); }

/* ── Field floating label ───────────────────────────────────────────── */
.bt-input-field-unit__field-label {
  position: absolute;
  pointer-events: none;
  inset-inline-start: var(--space-md);
  top: 50%;
  transform: translateY(-50%);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  transition: top 150ms cubic-bezier(0.4, 0, 0.2, 1),
              transform 150ms cubic-bezier(0.4, 0, 0.2, 1),
              font-size 150ms cubic-bezier(0.4, 0, 0.2, 1),
              font-weight 150ms cubic-bezier(0.4, 0, 0.2, 1),
              color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.bt-input-field-unit__field-label--floating {
  top: var(--space-sm);
  transform: none;
  font-size: var(--typography-font-size-2xs);
  font-weight: 600;
}
.bt-input-field-unit__right--active   .bt-input-field-unit__field-label { color: var(--color-brand-primary); }
.bt-input-field-unit__right--error    .bt-input-field-unit__field-label { color: var(--text-error); }
.bt-input-field-unit__right--disabled .bt-input-field-unit__field-label { color: var(--text-disabled); }

/* ── Text input ─────────────────────────────────────────────────────── */
.bt-input-field-unit__field {
  flex: 1;
  border: none;
  outline: none;
  background: transparent;
  font-family: inherit;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-primary);
  padding: 0;
  min-width: 0;
}
.bt-input-field-unit__field--has-label { padding-top: 12px; }
.bt-input-field-unit__field::placeholder { color: var(--text-secondary); font-weight: 400; }
.bt-input-field-unit__right--disabled .bt-input-field-unit__field { color: var(--text-disabled); cursor: not-allowed; }

/* ── Clear button — v-if + <Transition name="bt-input-clear"> ─────── */
.bt-input-field-unit__clear {
  display: flex;
  align-items: center;
  justify-content: center;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  color: var(--icon-primary);
}
.bt-input-field-unit__clear svg,
.bt-input-field-unit__clear img { width: 16px; height: 16px; display: block; }

/* ── Unit dropdown ──────────────────────────────────────────────────── */
.bt-input-field-unit__dropdown {
  position: absolute;
  top: calc(100% + 4px);
  inset-inline-start: 0;
  min-width: 120px;
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
  z-index: 100;
  overflow: hidden;
}
.bt-input-field-unit__dropdown-search {
  width: 100%;
  padding: 8px 12px;
  border: none;
  border-bottom: 1px solid var(--border-primary);
  outline: none;
  font-family: inherit;
  font-size: 13px;
  color: var(--text-primary);
  background: transparent;
  box-sizing: border-box;
}
.bt-input-field-unit__dropdown-search::placeholder { color: var(--text-secondary); }
.bt-input-field-unit__dropdown-item {
  padding: 10px 12px;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-primary);
  cursor: pointer;
  transition: background 100ms;
}
.bt-input-field-unit__dropdown-item:hover { background: var(--bg-subtle); }
.bt-input-field-unit__dropdown-item--selected {
  color: var(--color-brand-primary);
  font-weight: 600;
  background: var(--color-brand-primary-subtle);
}
.bt-input-field-unit__dropdown-item--selected:hover {
  background: var(--color-brand-primary-subtle);
}
.bt-input-field-unit__dropdown-empty {
  padding: 16px 12px;
  font-size: 13px;
  color: var(--text-secondary);
  text-align: center;
}

/* ── Helper / error text ────────────────────────────────────────────── */
.bt-input-field-unit__helper { margin-top: 4px; padding: 0 4px; font-size: var(--typography-font-size-xs); font-weight: 500; }
.bt-input-field-unit__helper-text { color: var(--text-secondary); }
.bt-input-field-unit__helper-text--error { color: var(--text-error); }
.bt-input-field-unit__required { color: var(--text-error); margin-inline-start: var(--space-2xs); }

/**
 * BTInputFieldUnit — Split input: unit selector (left) + text field (right).
 * Each panel has its own independent border that activates separately:
 * left border activates when the dropdown opens, right when the field is focused.
 *
 * Sliced from Figma node 702-3937.
 *
 * ## Usage:
 * ```tsx
 * <BTInputFieldUnit
 *   units={[{ label: 'IDR', value: 'IDR' }, { label: 'USD', value: 'USD' }]}
 *   unitLabel="Currency"
 *   label="Amount"
 *   value={amount}
 *   onChange={setAmount}
 *   formatter={(v, u) => u?.value === 'IDR' ? formatRupiah(v) : v}
 *   sanitizer={(v) => v.replace(/\D/g, '')}
 *   onUnitChanged={handleUnitChange}
 * />
 * ```
 */
import * as React from 'react';
import './BTInputFieldUnit.css';
import type {
  BTInputFieldUnitHandle,
  BTInputFieldUnitProps,
  BTInputFieldUnitOption,
} from './BTInputFieldUnit.types';

const cn = (...parts: Array<string | false | null | undefined>): string =>
  parts.filter(Boolean).join(' ');

export const BTInputFieldUnit = React.forwardRef<BTInputFieldUnitHandle, BTInputFieldUnitProps>(
  function BTInputFieldUnit(
    {
      units,
      selectedUnit,
      initialUnit,
      unitLabel,
      hasSearch = false,
      itemsFilter,
      onUnitChanged,
      label,
      value,
      onChange,
      formatter,
      sanitizer,
      keyboardType = 'text',
      hintText,
      clearable = true,
      validator,
      errorText,
      helperText,
      disabled = false,
      required = false,
      className,
    },
    ref,
  ) {
    // ── State ───────────────────────────────────────────────────────────────
    const [isDropdownOpen, setIsDropdownOpen] = React.useState(false);
    const [isFieldFocused, setIsFieldFocused] = React.useState(false);
    const [internalUnit, setInternalUnit] = React.useState<BTInputFieldUnitOption | undefined>(
      initialUnit ?? units[0],
    );
    const [errorInternal, setErrorInternal] = React.useState<string | null>(null);
    const [searchQuery, setSearchQuery] = React.useState('');

    const rootRef  = React.useRef<HTMLDivElement>(null);
    const fieldRef = React.useRef<HTMLInputElement>(null);

    // ── Derived ─────────────────────────────────────────────────────────────
    const currentUnit = selectedUnit !== undefined ? selectedUnit : internalUnit;
    const activeError = errorText ?? errorInternal ?? null;
    const hasError    = !!activeError;
    const showClear   = clearable && !!value && isFieldFocused && !disabled;
    const fieldLabelFloating = !!label && (isFieldFocused || !!value);

    // ── Click-outside to close dropdown ────────────────────────────────────
    React.useEffect(() => {
      function onClickOutside(e: MouseEvent) {
        if (rootRef.current && !rootRef.current.contains(e.target as Node)) {
          setIsDropdownOpen(false);
        }
      }
      document.addEventListener('mousedown', onClickOutside);
      return () => document.removeEventListener('mousedown', onClickOutside);
    }, []);

    // ── Display value (formatted) ───────────────────────────────────────────
    const displayValue = React.useMemo(() => {
      const raw = value ?? '';
      if (formatter && raw !== '') return formatter(raw, currentUnit ?? null);
      return raw;
    }, [value, formatter, currentUnit]);

    // ── Filtered units for search ────────────────────────────────────────────
    const filteredUnits = React.useMemo(() => {
      if (!hasSearch || !searchQuery) return units;
      if (itemsFilter) return itemsFilter(units, searchQuery);
      const q = searchQuery.toLowerCase();
      return units.filter((u) => u.label.toLowerCase().includes(q));
    }, [units, hasSearch, searchQuery, itemsFilter]);

    // ── Input type / inputMode ───────────────────────────────────────────────
    const inputType = keyboardType === 'tel' ? 'tel' : 'text';
    const inputMode: React.HTMLAttributes<HTMLInputElement>['inputMode'] =
      keyboardType === 'number'  ? 'numeric'
      : keyboardType === 'decimal' ? 'decimal'
      : keyboardType === 'tel'     ? 'tel'
      : keyboardType === 'url'     ? 'url'
      : undefined;

    // ── Handlers ─────────────────────────────────────────────────────────────
    function toggleDropdown() {
      if (disabled) return;
      if (!isDropdownOpen) setSearchQuery('');
      setIsDropdownOpen((open) => !open);
    }

    function selectUnit(option: BTInputFieldUnitOption) {
      setInternalUnit(option);
      onUnitChanged?.(option);
      setIsDropdownOpen(false);
    }

    function handleFieldInput(e: React.ChangeEvent<HTMLInputElement>) {
      const raw = e.target.value;
      const sanitized = sanitizer ? sanitizer(raw, currentUnit ?? null) : raw;
      onChange?.(sanitized);
    }

    function handleClear() {
      onChange?.('');
      setErrorInternal(null);
      fieldRef.current?.focus();
    }

    function validate(): boolean {
      if (!validator) return true;
      const result = validator(value ?? '', currentUnit ?? null);
      setErrorInternal(result ?? null);
      return result === null;
    }

    React.useImperativeHandle(ref, () => ({ validate }), [value, currentUnit, validator]);

    // ── CSS classes ──────────────────────────────────────────────────────────
    const leftClass = cn(
      'bt-input-field-unit__left',
      isDropdownOpen && 'bt-input-field-unit__left--active',
      hasError && 'bt-input-field-unit__left--error',
      disabled && 'bt-input-field-unit__left--disabled',
    );

    const dividerClass = cn(
      'bt-input-field-unit__divider',
      (isDropdownOpen || isFieldFocused) && 'bt-input-field-unit__divider--active',
      hasError && 'bt-input-field-unit__divider--error',
    );

    const rightClass = cn(
      'bt-input-field-unit__right',
      isFieldFocused && 'bt-input-field-unit__right--active',
      hasError && 'bt-input-field-unit__right--error',
      disabled && 'bt-input-field-unit__right--disabled',
    );

    return (
      <div ref={rootRef} className={cn('bt-input-field-unit__wrapper', className)}>
        <div className="bt-input-field-unit__row">

          {/* ── Left panel: unit selector ── */}
          <div
            className={leftClass}
            role="button"
            aria-expanded={isDropdownOpen}
            tabIndex={disabled ? -1 : 0}
            onClick={toggleDropdown}
            onKeyDown={(e) => {
              if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggleDropdown(); }
              if (e.key === 'Escape') setIsDropdownOpen(false);
            }}
          >
            {unitLabel && (
              <span className="bt-input-field-unit__unit-label">
                {unitLabel}
                {required && <span className="bt-input-field-unit__required">*</span>}
              </span>
            )}
            <div className="bt-input-field-unit__unit-row">
              <span className="bt-input-field-unit__unit-value">
                {currentUnit?.label ?? '—'}
              </span>
              <button
                type="button"
                className={cn(
                  'bt-input-field-unit__unit-chevron',
                  isDropdownOpen && 'bt-input-field-unit__unit-chevron--open',
                )}
                disabled={disabled}
                aria-label={isDropdownOpen ? 'Close unit selector' : 'Open unit selector'}
                tabIndex={-1}
                onClick={(e) => { e.stopPropagation(); toggleDropdown(); }}
              >
                <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
                  <path d="M7 10l5 5 5-5z" />
                </svg>
              </button>
            </div>

            {/* Dropdown list */}
            {isDropdownOpen && (
              <div className="bt-input-field-unit__dropdown" role="listbox">
                {hasSearch && (
                  <input
                    className="bt-input-field-unit__dropdown-search"
                    type="text"
                    placeholder="Search..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    onMouseDown={(e) => e.stopPropagation()}
                    onClick={(e) => e.stopPropagation()}
                    onKeyDown={(e) => {
                      if (e.key === 'Escape') { e.stopPropagation(); setIsDropdownOpen(false); }
                    }}
                  />
                )}
                {filteredUnits.length > 0 ? (
                  filteredUnits.map((option) => (
                    <div
                      key={option.value}
                      className={cn(
                        'bt-input-field-unit__dropdown-item',
                        currentUnit?.value === option.value &&
                          'bt-input-field-unit__dropdown-item--selected',
                      )}
                      role="option"
                      aria-selected={currentUnit?.value === option.value}
                      onMouseDown={(e) => { e.preventDefault(); selectUnit(option); }}
                    >
                      {option.label}
                    </div>
                  ))
                ) : (
                  <div className="bt-input-field-unit__dropdown-empty">No result found.</div>
                )}
              </div>
            )}
          </div>

          {/* ── Divider ── */}
          <div className={dividerClass} aria-hidden="true" />

          {/* ── Right panel: text field ── */}
          <div className={rightClass}>
            {label && (
              <label
                className={cn(
                  'bt-input-field-unit__field-label',
                  fieldLabelFloating && 'bt-input-field-unit__field-label--floating',
                )}
              >
                {label}
                {required && <span className="bt-input-field-unit__required">*</span>}
              </label>
            )}
            <div className="bt-input-field-unit__right-inner">
              <input
                ref={fieldRef}
                className={cn(
                  'bt-input-field-unit__field',
                  !!label && 'bt-input-field-unit__field--has-label',
                )}
                type={inputType}
                inputMode={inputMode}
                value={displayValue}
                placeholder={fieldLabelFloating || !label ? (hintText ?? '') : ''}
                disabled={disabled}
                onChange={handleFieldInput}
                onFocus={() => setIsFieldFocused(true)}
                onBlur={() => setIsFieldFocused(false)}
              />
              {showClear && (
                <button
                  type="button"
                  className="bt-input-field-unit__clear"
                  aria-label="Clear value"
                  tabIndex={-1}
                  onMouseDown={(e) => { e.preventDefault(); handleClear(); }}
                >
                  {/* Material cancel filled (circle with ×) */}
                  <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg" aria-hidden="true" fill="currentColor">
                    <path d="M12 2C6.47 2 2 6.47 2 12s4.47 10 10 10 10-4.47 10-10S17.53 2 12 2zm5 13.59L15.59 17 12 13.41 8.41 17 7 15.59 10.59 12 7 8.41 8.41 7 12 10.59 15.59 7 17 8.41 13.41 12 17 15.59z" />
                  </svg>
                </button>
              )}
            </div>
          </div>

        </div>

        {/* ── Helper / error text ── */}
        {(activeError || helperText) && (
          <div className="bt-input-field-unit__helper">
            <span
              className={cn(
                'bt-input-field-unit__helper-text',
                hasError && 'bt-input-field-unit__helper-text--error',
              )}
            >
              {activeError || helperText}
            </span>
          </div>
        )}
      </div>
    );
  },
);

