// ── Component ─────────────────────────────────────────────────────────────────
export const BTInputMultipleField = React.forwardRef<
  BTInputMultipleFieldHandle,
  BTInputMultipleFieldProps
>(function BTInputMultipleField(
  {
    value = [],
    items = [],
    label,
    type = 'wrap',
    required = false,
    disabled = false,
    errorText,
    helperText,
