  const [errorTextInternal, setErrorTextInternal] = React.useState<string | null>(null);

  // ── Derived state ──────────────────────────────────────────────────────────
  const tags     = value;
  const hasItems = items.length > 0;

  // Field is "active" when the native input is focused OR the dropdown is open
  const isActive = isFocused || isDropdownOpen;

  const hasContent = tags.length > 0 || inputValue.length > 0;

  const labelFloating = !!(label && (isActive || hasContent));

  // filteredItems: pre-filtered + checked-state-stamped list
  const filteredItems = React.useMemo<BTDropdownItem<string>[]>(() => {
    let filtered: BTDropdownItem<string>[];

    if (!hasSearch || !searchQuery) {
      filtered = items;
    } else if (itemsFilter) {
      filtered = itemsFilter(items, searchQuery);
    } else {
      const q = searchQuery.toLowerCase();
      filtered = items.filter(i => (i.label ?? '').toLowerCase().includes(q));
    }

    // Stamp checked state from current tags (match by item.value === tag.id)
    return filtered.map(item => ({
      ...item,
      checked: tags.some(t => t.id === item.value),
    }));
  }, [items, hasSearch, searchQuery, itemsFilter, tags]);

  // Active error: external errorText prop takes priority over internal validator result
  const activeError = errorText ?? errorTextInternal ?? null;

  // ── CSS classes ────────────────────────────────────────────────────────────
  const fieldClass = cn(
    'bt-input-multiple-field',
    `bt-input-multiple-field--${type}`,
    isActive  && 'bt-input-multiple-field--focused',
    !!activeError && 'bt-input-multiple-field--error',
    disabled  && 'bt-input-multiple-field--disabled',
  );

  // ── Overlay positioning ────────────────────────────────────────────────────
  // Sets the overlay width (tied to wrapper) via state.
  // top/left are handled by positionBelow() direct DOM mutations so that
  // smart flip (below ↔ above) works without re-render interference.
  function syncOverlayPosition() {
    if (!wrapperRef.current) return;
    const { width } = wrapperRef.current.getBoundingClientRect();
    setOverlayStyle({
      position: 'fixed',
      width:  `${width}px`,
      zIndex: 200,
    });
    // After state update → overlay re-renders with new width → positionBelow
    // re-anchors top/left (called from the isDropdownOpen useEffect below).
    if (overlayRef.current) {
      positionBelow(wrapperRef.current, overlayRef.current, { gap: 4, margin: 8 });
    }
  }

  // ── Height animation (wrap type) ───────────────────────────────────────────
  // Reads content.scrollHeight and explicitly sets the field container's height
  // so CSS `transition: height` can animate tag-row additions/removals.
  function syncFieldHeight() {
    if (type !== 'wrap' || !fieldRef.current) return;
    const content = fieldRef.current.querySelector<HTMLElement>(
      '.bt-input-multiple-field__content',
    );
    if (!content) return;
    const pad = labelFloating ? 8 : 0;
    const h   = Math.max(48, content.scrollHeight + pad);
    fieldRef.current.style.height = `${h}px`;
  }

  // ── Dropdown open / close ──────────────────────────────────────────────────
  function openDropdown() {
    if (disabled) return;
    syncOverlayPosition();
    setSearchQuery('');
    setIsDropdownOpen(true);
  }

  function closeDropdown() {
    setIsDropdownOpen(false);
  }

  function toggleDropdown() {
    isDropdownOpen ? closeDropdown() : openDropdown();
  }

  // ── Smart-flip positioning after portal mounts ────────────────────────────
  // The portal renders on the NEXT paint after isDropdownOpen → true.
  // positionBelow runs in rAF so the overlay height is measurable.
  React.useEffect(() => {
    if (!isDropdownOpen) return;
    const id = requestAnimationFrame(() => {
      if (wrapperRef.current && overlayRef.current) {
        positionBelow(wrapperRef.current, overlayRef.current, { gap: 4, margin: 8 });
      }
    });
    return () => cancelAnimationFrame(id);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isDropdownOpen]);

  // ── Scroll / resize re-anchor while open ─────────────────────────────────
  React.useEffect(() => {
    if (!isDropdownOpen) return;
    function reposition() {
      if (wrapperRef.current && overlayRef.current) {
        positionBelow(wrapperRef.current, overlayRef.current, { gap: 4, margin: 8 });
      }
    }
    document.addEventListener('scroll', reposition, true);
    window.addEventListener('resize', reposition);
    return () => {
      document.removeEventListener('scroll', reposition, true);
      window.removeEventListener('resize', reposition);
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isDropdownOpen]);

  // ── Click-outside closes the dropdown ─────────────────────────────────────
  React.useEffect(() => {
    if (!isDropdownOpen) return;
    function onMouseDown(e: MouseEvent) {
      const target = e.target as Node;
      const insideWrapper = wrapperRef.current?.contains(target) ?? false;
      const insideOverlay = overlayRef.current?.contains(target) ?? false;
      if (!insideWrapper && !insideOverlay) closeDropdown();
    }
    document.addEventListener('mousedown', onMouseDown);
    return () => document.removeEventListener('mousedown', onMouseDown);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isDropdownOpen]);

  // ── Escape key while open ──────────────────────────────────────────────────
  React.useEffect(() => {
    if (!isDropdownOpen) return;
    function onKeyDown(e: KeyboardEvent) {
      if (e.key === 'Escape') closeDropdown();
    }
    document.addEventListener('keydown', onKeyDown);
    return () => document.removeEventListener('keydown', onKeyDown);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isDropdownOpen]);

  // ── Height + overlay re-anchor after every relevant state change ───────────
  React.useEffect(() => {
    requestAnimationFrame(() => {
      syncFieldHeight();
      if (isDropdownOpen) {
        syncOverlayPosition();
        setTimeout(() => {
          if (isDropdownOpen) syncOverlayPosition();
        }, 210);
      }
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [tags, isActive, labelFloating, type]);

  // ── ResizeObserver — live-track wrapper resize while dropdown is open ──────
  React.useEffect(() => {
    if (!wrapperRef.current) return;
    const ro = new ResizeObserver(() => {
      if (isDropdownOpen) syncOverlayPosition();
    });
    ro.observe(wrapperRef.current);
    // Initial sync
    syncFieldHeight();
    return () => ro.disconnect();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // ── Focus ──────────────────────────────────────────────────────────────────
  function onBodyClick() {
    if (disabled) return;
    // Set isFocused first so the body v-show equivalent (display:none guard) is
    // lifted before we attempt to focus the input.
    setIsFocused(true);
    requestAnimationFrame(() => inputRef.current?.focus());
  }

  function onInputFocus() { setIsFocused(true); }
  function onInputBlur()  { setIsFocused(false); }

  // ── Tag operations ─────────────────────────────────────────────────────────
  // Enter: commit typed text as a free-text tag
  function onEnter(e: React.KeyboardEvent<HTMLInputElement>) {
    e.preventDefault();
    const v = inputValue.trim();
    if (!v) return;
    onChange?.([...tags, { label: v, id: crypto.randomUUID() }]);
    setInputValue('');
  }

  // Backspace on empty cursor: remove the last tag
  function onBackspace() {
    if (inputValue === '' && tags.length > 0) {
      onChange?.(tags.slice(0, -1));
    }
  }

  function removeTag(tag: BTTagItem) {
    onChange?.(tags.filter(t => t.id !== tag.id));
  }

  // Clear all tags + typed input
  function clearAll(e: React.MouseEvent) {
    e.preventDefault();
    onChange?.([]);
    setInputValue('');
    requestAnimationFrame(() => inputRef.current?.focus());
  }

  // ── Predefined item toggled from BTDropdownList ────────────────────────────
  function onItemSelect(val: string) {
    const existing = tags.find(t => t.id === val);
    if (existing) {
      // Deselect: remove from tag list
      onChange?.(tags.filter(t => t.id !== val));
    } else {
      // Select: find item label and add as tag
      const item = items.find(i => i.value === val);
      if (!item?.label) return;
      onChange?.([...tags, { label: item.label, id: val }]);
    }
  }

  // ── Validation ─────────────────────────────────────────────────────────────
  function validate(): boolean {
    if (!validator) return true;
    const result = validator(tags);
    setErrorTextInternal(result ?? null);
    return result === null;
  }

  React.useImperativeHandle(ref, () => ({ validate }));

  // ── Render ─────────────────────────────────────────────────────────────────
  return (
    <div ref={wrapperRef} className="bt-input-multiple-field__wrapper">

      {/* Field container: flex-row, height controlled via JS (syncFieldHeight) */}
      <div
        ref={fieldRef}
        className={fieldClass}
        onClick={onBodyClick}
      >
        {/* Content column: label + body (tags + cursor) */}
        <div className="bt-input-multiple-field__content">

          {/* Label: inline flow, 14px resting → 12px floating */}
          {label && (
            <label
              htmlFor={fieldInputId}
              className={cn(
                'bt-input-multiple-field__label',
                labelFloating && 'bt-input-multiple-field__label--floating',
              )}
            >
              {label}
              {required && (
                <span className="bt-input-multiple-field__required">*</span>
              )}
            </label>
          )}

          {/* Body: tags + cursor — shown when label is floating or there is no label */}
          <div
            className="bt-input-multiple-field__body"
            style={{ display: labelFloating || !label ? undefined : 'none' }}
          >
            {/* Tags: × icon only when the field is active (focused / dropdown open).
                The onMouseDown.preventDefault keeps the input focused when the
                user clicks the × button — without it, mousedown steals focus from
                the input before click fires. */}
            {tags.map(tag => (
              <span
                key={tag.id ?? tag.label}
                onMouseDown={(e) => e.preventDefault()}
              >
                <BTTag
                  label={tag.label}
                  onRemove={isActive && !disabled ? () => removeTag(tag) : undefined}
                />
              </span>
            ))}

            {/* Inline text cursor — hidden when field is inactive so it doesn't
                leave a blank 20px row below the tags in the resting/filled state */}
            <input
              id={fieldInputId}
              ref={inputRef}
              className="bt-input-multiple-field__cursor"
              value={inputValue}
              disabled={disabled}
              placeholder={!hasContent && !label ? 'Type and press Enter...' : ''}
              style={{ display: isActive ? undefined : 'none' }}
              onChange={(e) => setInputValue(e.target.value)}
              onFocus={onInputFocus}
              onBlur={onInputBlur}
              onKeyDown={(e) => {
                if (e.key === 'Enter')     onEnter(e);
                if (e.key === 'Backspace') onBackspace();
              }}
              onClick={(e) => e.stopPropagation()}
            />
          </div>
        </div>

        {/* Right actions: clear-all (×) + chevron */}
        <div className="bt-input-multiple-field__actions">

          {/* Clear-all: shown only when active AND there are tags to clear */}
          {isActive && tags.length > 0 && (
            <button
              type="button"
              className="bt-input-multiple-field__clear-all"
              aria-label="Clear all"
              tabIndex={-1}
              onMouseDown={clearAll}
            >
              {/* Material cancel icon (filled circle with ×) */}
              <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
                <path d="M12 2C6.47 2 2 6.47 2 12s4.47 10 10 10 10-4.47 10-10S17.53 2 12 2zm5 13.59L15.59 17 12 13.41 8.41 17 7 15.59 10.59 12 7 8.41 8.41 7 12 10.59 15.59 7 17 8.41 13.41 12 17 15.59z"/>
              </svg>
            </button>
          )}

          {/* Chevron: ↓ when closed, ↑ when open (separate paths, no rotation) */}
          {hasItems && (
            <button
              type="button"
              className="bt-input-multiple-field__chevron"
              disabled={disabled}
              aria-expanded={isDropdownOpen}
              aria-label={isDropdownOpen ? 'Close options' : 'Open options'}
              onClick={(e) => { e.stopPropagation(); toggleDropdown(); }}
            >
              {!isDropdownOpen ? (
                /* keyboard_arrow_down */
                <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
                  <path d="M7.41 8.59L12 13.17l4.59-4.58L18 10l-6 6-6-6 1.41-1.41z"/>
                </svg>
              ) : (
                /* keyboard_arrow_up */
                <svg viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
                  <path d="M7.41 15.41L12 10.83l4.59 4.58L18 14l-6-6-6 6 1.41 1.41z"/>
                </svg>
              )}
            </button>
          )}
        </div>
      </div>

      {/* Dropdown overlay — rendered in a portal so it escapes stacking contexts */}
      {isDropdownOpen && createPortal(
        <div
          ref={overlayRef}
          className="bt-input-mf-overlay"
          style={overlayStyle}
        >
          <BTDropdownList
            items={filteredItems}
            variant="checkbox"
            searchable={hasSearch}
            searchQuery={searchQuery}
            onSearchChange={setSearchQuery}
            emptyLabel={emptyLabel}
            onSelect={onItemSelect}
          />
        </div>,
        document.body,
      )}

      {/* Helper / error text */}
      {(activeError || helperText) && (
        <div className="bt-input-multiple-field__helper">
          <span
            className={cn(
              'bt-input-multiple-field__helper-text',
              !!activeError && 'bt-input-multiple-field__helper-text--error',
            )}
          >
            {activeError || helperText}
          </span>
        </div>
      )}
    </div>
  );
});

BTInputMultipleField.displayName = 'BTInputMultipleField';

import type { BTTagItem } from '../../tag/BTTag.types';
import type { BTDropdownItem } from '../../dropdown-list/BTDropdownList.types';

export type BTInputMultipleFieldType = 'wrap' | 'scroll';

/**
 * Props for {@link BTInputMultipleField}.
 *
 * @example
 * ```tsx
 * <BTInputMultipleField
 *   value={selectedTags}
 *   onChange={setSelectedTags}
 *   label="Frameworks"
 *   items={frameworkItems}
 *   hasSearch
 * />
 * ```
 *
 * @example Free-text only (no predefined items)
 * ```tsx
 * <BTInputMultipleField value={tags} onChange={setTags} label="Skills" />
 * ```
 */
export interface BTInputMultipleFieldProps {
  /**
   * Current list of tags. The component calls onChange with the updated list
   * on every change.
   */
  value?: BTTagItem[];
  /**
   * Predefined selectable options shown in a checkbox dropdown.
   * Each option is toggled into/out of the tag list.
   */
  items?: BTDropdownItem<string>[];
  /**
   * Floating label — sits centered when empty/idle, floats small on focus
   * or when the field has content.
   */
  label?: string;
  /**
   * Tag layout.
   * - 'wrap'   — tags flow into multiple rows; field height grows.
   * - 'scroll' — single fixed-height row; tags scroll horizontally.
   * @default 'wrap'
   */
  type?: BTInputMultipleFieldType;
  /** Appends " *" (red) to the label. @default false */
  required?: boolean;
  /** Disables all interaction and dims the field. @default false */
  disabled?: boolean;
  /** Red border + validation text shown below the field. */
  errorText?: string;
  /** Text shown below the field when there is no error. */
  helperText?: string;
  /**
   * Show a search input at the top of the predefined-items dropdown.
   * @default false
   */
  hasSearch?: boolean;
  /**
   * Custom filter applied when hasSearch is true and the user types.
   * Receives the full items list and current query; returns filtered subset.
   * Defaults to case-insensitive label.includes(query).
   */
  itemsFilter?: (
    items: BTDropdownItem<string>[],
    query: string,
  ) => BTDropdownItem<string>[];
  /**
   * Text shown beneath the empty-state illustration in the dropdown.
   * @default 'No result found.'
   */
  emptyLabel?: string;
  /** Called with the updated tag list on every change. */
  onChange?: (tags: BTTagItem[]) => void;
  /**
   * Called on validate(). Return null for valid, or an error string.
   * The returned string is shown below the field as an error.
   */
  validator?: (tags: BTTagItem[]) => string | null;
}

/**
 * Imperative handle exposed via forwardRef.
 * Access via `ref.current.validate()`.
 */
export interface BTInputMultipleFieldHandle {
  /** Runs the validator; shows the error inline; returns true if valid. */
  validate: () => boolean;
}

export { BTInputMultipleField } from './BTInputMultipleField';
export type {
  BTInputMultipleFieldProps,
  BTInputMultipleFieldType,
  BTInputMultipleFieldHandle,
} from './BTInputMultipleField.types';

/* BTInputRichEditor — Figma node 665-2254 */

/* ── Wrapper ──────────────────────────────────────────────────────────────── */
.bt-input-rich-editor {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  width: 100%;
}

/* ── Content box ──────────────────────────────────────────────────────────── */
.bt-input-rich-editor__box {
  position: relative;
  display: flex;
  flex-direction: column;
  /* Figma Default state: border.tertiary (#c1c6cd = neutral-300) */
  border: 1px solid var(--border-tertiary);
  border-radius: var(--radius-md);
  background: var(--bg-primary);
  /* No fixed max-height — box grows naturally to fit editor + attachment cards.
     Removed overflow:hidden so the editor is never clipped. */
  padding: 8px;
  gap: var(--space-xs);
  transition: border-color 0.15s;
  cursor: text;
}

/* State: focused/active */
.bt-input-rich-editor--active .bt-input-rich-editor__box {
  border-color: var(--color-brand-primary);
}

/* State: error */
.bt-input-rich-editor--error .bt-input-rich-editor__box {
  border-color: var(--color-ext-error);
}

/* State: disabled */
.bt-input-rich-editor--disabled .bt-input-rich-editor__box {
  background: var(--bg-subtle);
  border-color: var(--border-disabled);
  cursor: not-allowed;
}

/* ── Label ────────────────────────────────────────────────────────────────── */
.bt-input-rich-editor__label {
  font-size: var(--typography-font-size-sm);  /* 14px — empty/default state */
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  transition: font-size 0.15s, color 0.15s;
  pointer-events: none;
  user-select: none;
  flex-shrink: 0;
}

/* Label floats when filled or active */
.bt-input-rich-editor--filled .bt-input-rich-editor__label,
.bt-input-rich-editor--active .bt-input-rich-editor__label {
  font-size: var(--typography-font-size-xs);  /* 12px */
}

/* Label color: active/focused → brand primary (matches BTInputTextArea) */
.bt-input-rich-editor--active .bt-input-rich-editor__label {
  color: var(--color-brand-primary);
}

/* Label color: error state */
.bt-input-rich-editor--error .bt-input-rich-editor__label {
  color: var(--text-error);
}

/* Label color: disabled */
.bt-input-rich-editor--disabled .bt-input-rich-editor__label {
  color: var(--text-primary);
}

.bt-input-rich-editor__required {
  color: var(--text-error);
}

/* ── Header row (label + clear button) ───────────────────────────────────── */
.bt-input-rich-editor__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-xs);
  flex-shrink: 0;
}

/* ── Clear button ─────────────────────────────────────────────────────────── */
.bt-input-rich-editor__clear {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  color: var(--icon-primary);
  transition: opacity 0.1s;
}

.bt-input-rich-editor__clear:hover {
  opacity: 0.7;
}

.bt-input-rich-editor__clear img {
  width: 16px;
  height: 16px;
  display: block;
}

/* ── Editor area (Quill mount point) ─────────────────────────────────────── */
/*
 * When Quill initializes, it turns this div into .ql-container and creates
 * .ql-editor inside it. We reset all Quill defaults here.
 *
 * No flex:1 — the box has no fixed height to flex against (it grows with content).
 * The editor uses a concrete min-height instead so it is always visible.
 */
.bt-input-rich-editor__editor {
  min-height: 56px;   /* always tappable even when empty */
  display: flex;
  flex-direction: column;
}

/* Quill makes the mount div the .ql-container — reset its injected styles */
.bt-input-rich-editor__editor.ql-container {
  border: none !important;
  box-shadow: none !important;
  font-family: var(--typography-font-family-sans) !important;
  font-size: var(--typography-font-size-sm) !important;
  height: auto !important;
}

/* Override Quill editor inner element */
.bt-input-rich-editor__editor .ql-editor {
  padding: 0 !important;
  outline: none !important;       /* ← KEY FIX: removes browser blue focus ring */
  border: none !important;
  box-shadow: none !important;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  min-height: 32px;
  max-height: 120px;   /* cap the text area height; box itself grows for attachment cards */
  overflow-y: auto;
  white-space: pre-wrap;
  word-wrap: break-word;
}

/* Placeholder text */
.bt-input-rich-editor__editor .ql-editor.ql-blank::before {
  font-style: normal;
  color: var(--text-secondary);
  pointer-events: none;
  inset-inline-start: 0;
  inset-inline-end: 0;
}

/* Paragraph margin reset */
.bt-input-rich-editor__editor .ql-editor p {
  margin: 0;
}

/* Static content in disabled+filled state (Quill not initialized) */
.bt-input-rich-editor__editor--static {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  overflow-y: auto;
}

.bt-input-rich-editor__editor--static p {
  margin: 0;
}

/* ── Toolbar ──────────────────────────────────────────────────────────────── */
/* Figma toolbar: bg-primary, border-primary, 36px height, 5px radius, 8px 12px padding */
.bt-input-rich-editor__toolbar {
  display: flex;
  align-items: center;
  height: 36px;
  padding: 8px 12px;
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: 5px;
  flex-shrink: 0;
  box-sizing: border-box;
}

/* Scrollable icon area — takes remaining width, hides scrollbar */
.bt-input-rich-editor__toolbar-main {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  flex: 1;
  min-width: 0;
  overflow-x: auto;
  scrollbar-width: none;
}

.bt-input-rich-editor__toolbar-main::-webkit-scrollbar {
  display: none;
}

/* Pinned end group — delete always at far right */
.bt-input-rich-editor__toolbar-end {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  flex-shrink: 0;
}

/* Toolbar button — 16×16, no padding: SVG viewBox already includes Figma frame padding */
.bt-input-rich-editor__tool {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  border-radius: 3px;
  color: var(--text-primary);
  transition: background 0.1s;
}

.bt-input-rich-editor__tool:hover {
  background: var(--bg-subtle);
}

.bt-input-rich-editor__tool--active {
  background: var(--bg-secondary);
}

.bt-input-rich-editor__tool img {
  width: 16px;
  height: 16px;
  display: block;
  /* object-fit: contain as safety net — prevents any layout-driven stretching */
  object-fit: contain;
}

/* Toolbar separator — vertical 1px line, full toolbar height */
.bt-input-rich-editor__separator {
  width: 1px;
  align-self: stretch;
  background: var(--border-tertiary);
  flex-shrink: 0;
}

/* ── Footer ───────────────────────────────────────────────────────────────── */
.bt-input-rich-editor__footer {
  display: flex;
  align-items: center;
