/* ─────────────────────────────────────────────────────────────────────────────
   BTInputTextArea — Figma node 487-6751

   Label: always top-left at 14px; shrinks to 12px when focused or non-empty.
   Cancel: position:absolute inside body, right:0 (= 8px from wrapper border).
   Scrollbar: custom overlay, starts 8px below cancel bottom (top: 26px in body).
   Height: JS-controlled, min 62px (textarea) = 80px wrapper, max 142px = 160px wrapper.
   ───────────────────────────────────────────────────────────────────────────── */

.bt-input-text-area {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  font-family: var(--typography-font-family-sans);
  width: 100%;
}

/* ── Wrapper: block container (not flex-row — cancel is no longer a sibling) ── */
.bt-input-text-area__wrapper {
  padding: 8px;
  border: 1px solid var(--border-tertiary);
  border-radius: var(--radius-sm);
  background: var(--bg-primary);
  box-sizing: border-box;
  min-height: 80px;
  max-height: 160px;
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
  overflow: hidden;
}

.bt-input-text-area__wrapper--focused  { border-color: var(--color-brand-primary); }
.bt-input-text-area__wrapper--error    { border-color: var(--text-error); }
.bt-input-text-area__wrapper--disabled { background: var(--bg-subtle); }

/* ── Body: position:relative anchor for label + cancel ── */
.bt-input-text-area__body {
  position: relative;
}

/* ── Label: always pinned top-left — font-size changes on focus/fill (like BTInput) ──
   Resting (empty + unfocused): 14px / line-height 20px — full size at top-left.
   Active (--floating = focused OR has value): 12px / line-height 16px — shrinks in
   layout, content below shifts up. Matches BTInput's floating-label density exactly.
   background: matches surface so scrolled text beneath doesn't bleed through.
   right: 20px = cancel (16px) + gap (4px). ── */
.bt-input-text-area__label {
  position: absolute;
  top: 0;
  inset-inline-start: 0;
  inset-inline-end: 20px;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-sm);
  color: var(--text-secondary);
  pointer-events: none;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  background: var(--bg-primary);
  z-index: 1;
  transition: font-size 150ms cubic-bezier(0.4, 0, 0.2, 1),
              line-height 150ms cubic-bezier(0.4, 0, 0.2, 1),
              color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

/* Active state — matches BTInput's floating: 12px / 16px line-height */
.bt-input-text-area__label--floating {
  font-size: var(--typography-font-size-xs);
  line-height: var(--typography-line-height-xs);
}

/* Focused + active: label turns brand-primary */
.bt-input-text-area__wrapper--focused .bt-input-text-area__label--floating {
  color: var(--color-brand-primary);
}

.bt-input-text-area__label--error    { color: var(--text-error) !important; }
.bt-input-text-area__label--disabled { color: var(--text-disabled); background: var(--bg-subtle); }

.bt-input-text-area__required {
  color: var(--text-error);
  margin-inline-start: var(--space-2xs);
}

/* ── Textarea ──
   padding-right: 20px = cancel (16px) + gap (4px). Native scrollbar hidden — custom overlay used.
   No flex:1 — JS inline height must not be overridden. ── */
.bt-input-text-area__field {
  display: block;
  width: 100%;
  min-height: 62px;
  box-sizing: border-box;
  padding-block: 8px;
  padding-inline-end: 20px;
  padding-inline-start: 0;
  border: none;
  outline: none;
  background: transparent;
  color: var(--text-primary);
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-sm);
  resize: none;
  overflow-y: hidden;
  transition: height 150ms cubic-bezier(0.4, 0, 0.2, 1);
  /* Hide native scrollbar — custom overlay handles it */
  scrollbar-width: none;
}

/* Resting: label is 14px/20px → padding-top matches so content starts right below. */
.bt-input-text-area__field--has-label {
  padding-top: 20px;
}

/* Floating: label shrinks to 12px/16px → padding-top follows so gap stays the same. */
.bt-input-text-area__field--label-floating {
  padding-top: 16px;
}

.bt-input-text-area__field::placeholder { color: var(--text-secondary); }
.bt-input-text-area__field:disabled     { color: var(--text-disabled); cursor: not-allowed; }
.bt-input-text-area__field::-webkit-scrollbar { display: none; }

/* ── Cancel button: absolute inside body, right:0 = 8px from wrapper border (via padding).
   top: 2px  = vertically centered with the 20px floating label.
   z-index: 3 = above scrollbar track, label, and textarea content.
   Visibility driven by v-if + <Transition name="bt-input-clear"> — no toggle class needed. ── */
.bt-input-text-area__clear {
  position: absolute;
  inset-inline-end: 0;
  top: var(--space-2xs);
  z-index: 3;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  border: none;
  background: none;
  cursor: pointer;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--icon-primary);
}

.bt-input-text-area__clear img,
.bt-input-text-area__clear svg {
  width: 16px;
  height: 16px;
  display: block;
}

/* ── Custom scrollbar ──
   Track: absolute inside body, right:0 (aligns with cancel button's right edge).
   top: 26px = cancel top (2px) + cancel height (16px) + gap (8px).
   Shown only when textarea content overflows max height.
   z-index: 2 = above label/textarea, below cancel button. ── */
.bt-input-text-area__scrollbar-track {
  position: absolute;
  inset-inline-end: 0;
  top: 26px;
  bottom: 0;
  width: 4px;
  pointer-events: none;
  z-index: 2;
}

.bt-input-text-area__scrollbar-thumb {
  position: absolute;
  left: 0;
  right: 0;
  border-radius: var(--radius-xs);
  background: var(--bg-subtlest);   /* matches BTScrollbar thumb token */
  min-height: 20px;
  pointer-events: auto;             /* draggable even though track is pointer-events:none */
  cursor: ns-resize;
  transition: background 150ms ease;
}

.bt-input-text-area__scrollbar-thumb:hover {
  background: var(--text-disabled); /* matches BTScrollbar hover token */
}

/* ── Footer ── */
.bt-input-text-area__footer {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: var(--space-sm);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-input-text-area__error      { flex: 1; color: var(--text-error); }
.bt-input-text-area__helper     { flex: 1; color: var(--text-secondary); }
.bt-input-text-area__char-count { flex-shrink: 0; color: var(--text-secondary); }

/**
 * BTInputTextArea — auto-growing textarea with floating label.
 *
 * Label: always pinned top-left at 14px. Shrinks to 12px when focused or non-empty.
 *        Color turns brand-primary when focused.
 *
 * Cancel: position:absolute, right:0 in body (= 8px from wrapper border via padding).
 * Custom scrollbar: 4px overlay track starting 8px below cancel's bottom (body top:26px).
 *
 * Height animation (3-phase):
 * Phase 1 — pin wrapper height, disable transition, shrink to MIN_HEIGHT to measure
 *            scrollHeight accurately.
 * Phase 2 — unpin wrapper + restore prevH atomically in one reflow so the browser
 *            never paints the collapsed state (footer flicker fix).
 * Phase 3 — restore transition + set target → browser animates.
 *
 * scheduleAdjust flag prevents double-call (onChange + useEffect both fire on user
 * input), which would cause Phase-1 snap to cancel a running animation.
 *
 * ## Usage
 * ```tsx
 * <BTInputTextArea
 *   value={desc}
 *   onChange={setDesc}
 *   label="Description"
 *   required
 *   maxLength={256}
 *   validator={(v) => v.length < 10 ? 'Too short' : null}
 * />
 * ```
 */
import * as React from 'react';
import './BTInputTextArea.css';
import type { BTInputTextAreaHandle, BTInputTextAreaProps } from './BTInputTextArea.types';
import cancelFillIcon from './icons/cancel-fill.svg';

const MIN_HEIGHT = 62;   // → 80px wrapper  (62 + 2×8 pad + 2×1 border)
const MAX_HEIGHT = 142;  // → 160px wrapper

export const BTInputTextArea = React.forwardRef<BTInputTextAreaHandle, BTInputTextAreaProps>(
  function BTInputTextArea(
    {
      value,
      label,
      placeholder,
      required = false,
      disabled = false,
      errorText,
      helperText,
      maxLength,
      // rows kept for API compat — auto-grow handles height
      rows: _rows,
      onChange,
      onClear,
      validator,
      className,
    },
    ref,
  ) {
    const fieldId = React.useId();

    const textareaRef    = React.useRef<HTMLTextAreaElement>(null);
    const scrollTrackRef = React.useRef<HTMLDivElement>(null);

    const [isFocused, setIsFocused]         = React.useState(false);
    const [errorInternal, setErrorInternal] = React.useState<string | null>(null);

    // ── Custom scrollbar state ─────────────────────────────────────────────────
    const [showScrollbar, setShowScrollbar] = React.useState(false);
    const [thumbHeight, setThumbHeight]     = React.useState(0);
    const [thumbTop, setThumbTop]           = React.useState(0);

    const activeError  = errorText ?? errorInternal ?? null;
    const isEmpty      = !value;
    const showFloating = isFocused || !isEmpty;
    const showClear    = isFocused && !isEmpty && !disabled;

    // ── Scrollbar ──────────────────────────────────────────────────────────────
    function updateScrollbar() {
      const el = textareaRef.current;
      if (!el) return;

      const { scrollHeight, clientHeight, scrollTop } = el;
      const overflows = scrollHeight > clientHeight + 1;
      setShowScrollbar(overflows);

      if (!overflows) return;

      const track  = scrollTrackRef.current;
      const trackH = track ? track.clientHeight : 0;
      if (trackH <= 0) {
        // showScrollbar just toggled true but the track may not be measured yet
        // (display:none → clientHeight = 0). Retry after the next paint.
        requestAnimationFrame(updateScrollbar);
        return;
      }

      const ratio      = clientHeight / scrollHeight;
      const tH         = Math.max(20, ratio * trackH);
      const maxTop     = trackH - tH;
      const scrollable = scrollHeight - clientHeight;
      setThumbHeight(tH);
      setThumbTop(scrollable > 0 ? (scrollTop / scrollable) * maxTop : 0);
    }

    // ── Scrollbar drag ─────────────────────────────────────────────────────────
    function handleThumbMousedown(e: React.MouseEvent) {
      e.preventDefault();
      const elRaw   = textareaRef.current;
      const track   = scrollTrackRef.current;
      if (!elRaw || !track) return;

      // Capture non-null so TypeScript narrows correctly inside async closures.
      const el: HTMLTextAreaElement = elRaw;

      const startY         = e.clientY;
      const startScrollTop = el.scrollTop;
      const trackH         = track.clientHeight;
      const scrollable     = el.scrollHeight - el.clientHeight;

      function onMove(ev: MouseEvent) {
        const delta = ev.clientY - startY;
        el.scrollTop = Math.max(0, Math.min(startScrollTop + (delta / trackH) * scrollable, scrollable));
        updateScrollbar();
      }
      function onUp() {
        document.removeEventListener('mousemove', onMove);
        document.removeEventListener('mouseup', onUp);
      }
      document.addEventListener('mousemove', onMove);
      document.addEventListener('mouseup', onUp);
    }

    // ── Height animation ───────────────────────────────────────────────────────
    const adjustPendingRef = React.useRef(false);

    function adjustHeight() {
      const el = textareaRef.current;
      if (!el) return;

      const prevH = parseInt(el.style.height, 10) || el.offsetHeight || MIN_HEIGHT;

      // Pin wrapper height so Phase 1 never collapses the outer layout.
      // Without this, shrinking the textarea also shrinks the wrapper,
      // which shifts the footer (char counter) up — browser can paint that
      // intermediate state causing the visible "flicker".
      const wrapper = el.closest<HTMLElement>('.bt-input-text-area__wrapper');
      if (wrapper) wrapper.style.height = `${wrapper.offsetHeight}px`;

      // Phase 1: measure content height.
      // Shrink to MIN_HEIGHT so scrollHeight reflects true content size even
      // when textarea is currently taller than its content (e.g. after deletion).
      el.style.transition = 'none';
      el.style.height     = `${MIN_HEIGHT}px`;
      void el.offsetHeight; // sync reflow

      const scrollH = el.scrollHeight;
      const target  = Math.min(Math.max(scrollH, MIN_HEIGHT), MAX_HEIGHT);
      el.style.overflowY = scrollH > MAX_HEIGHT ? 'auto' : 'hidden';

      // Phase 2: unpin wrapper + restore prevH in ONE reflow.
      // Releasing wrapper.style.height and setting textarea back to prevH before
      // the forced reflow means the browser computes only the prevH layout —
      // it never paints the collapsed (MIN_HEIGHT) wrapper state.
      if (wrapper) wrapper.style.height = '';
      el.style.height = `${prevH}px`;
      void el.offsetHeight; // sync reflow — browser commits prevH

      // Phase 3: animate
      el.style.transition = ''; // restore CSS transition:height 150ms
      el.style.height     = `${target}px`;

      // Update custom scrollbar after height settles
      requestAnimationFrame(updateScrollbar);
    }

    function scheduleAdjust() {
      if (adjustPendingRef.current) return;
      adjustPendingRef.current = true;
      requestAnimationFrame(() => {
        adjustPendingRef.current = false;
        adjustHeight();
      });
    }

    // Mirror Vue's `watch(() => props.modelValue, scheduleAdjust)`
    React.useEffect(() => {
      scheduleAdjust();
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [value]);

    // ── Handlers ───────────────────────────────────────────────────────────────
    function handleChange(e: React.ChangeEvent<HTMLTextAreaElement>) {
      setErrorInternal(null);
      onChange?.(e.target.value);
      scheduleAdjust();
    }

    function handleClear() {
      onChange?.('');
      onClear?.();
      setErrorInternal(null);
      requestAnimationFrame(() => {
        adjustHeight();
        textareaRef.current?.focus();
      });
    }

    // ── Imperative handle ──────────────────────────────────────────────────────
    function validate(): boolean {
      if (!validator) return true;
      const result = validator(value ?? '');
      setErrorInternal(result ?? null);
      return result === null;
    }

    React.useImperativeHandle(ref, () => ({ validate }), [value, validator]);

    // ── Class helpers ──────────────────────────────────────────────────────────
    const wrapperClass = [
      'bt-input-text-area__wrapper',
      isFocused && !activeError ? 'bt-input-text-area__wrapper--focused' : '',
      activeError               ? 'bt-input-text-area__wrapper--error'   : '',
      disabled                  ? 'bt-input-text-area__wrapper--disabled' : '',
    ].filter(Boolean).join(' ');

    const labelClass = [
      'bt-input-text-area__label',
      showFloating  ? 'bt-input-text-area__label--floating'  : '',
      activeError   ? 'bt-input-text-area__label--error'     : '',
      disabled      ? 'bt-input-text-area__label--disabled'  : '',
    ].filter(Boolean).join(' ');

    const fieldClass = [
      'bt-input-text-area__field',
      label                    ? 'bt-input-text-area__field--has-label'      : '',
      label && showFloating    ? 'bt-input-text-area__field--label-floating' : '',
    ].filter(Boolean).join(' ');

    const showFooter = activeError || helperText || maxLength !== undefined;

    return (
      <div className={['bt-input-text-area', className].filter(Boolean).join(' ')}>

        <div className={wrapperClass}>
          {/* Body: position:relative anchor for label + cancel (both absolute) */}
          <div className="bt-input-text-area__body">

            {/* Label: floats from inside content area to top-left on focus/fill */}
            {label && (
              <label htmlFor={fieldId} className={labelClass}>
                {label}
                {required && <span className="bt-input-text-area__required">*</span>}
              </label>
            )}

            {/* Textarea: padding-top:20px reserves space for the label (16px) + 4px gap */}
            <textarea
              id={fieldId}
              ref={textareaRef}
              rows={1}
              className={fieldClass}
              value={value ?? ''}
              placeholder={isFocused ? (placeholder ?? '') : ''}
              disabled={disabled}
              maxLength={maxLength}
              onChange={handleChange}
              onFocus={() => setIsFocused(true)}
              onBlur={() => setIsFocused(false)}
              onScroll={updateScrollbar}
            />

            {/* Cancel: absolute inside body, right:0 = 8px from wrapper border.
                position:absolute means conditional render doesn't shift layout. */}
            {showClear && (
              <button
                type="button"
                className="bt-input-text-area__clear"
                tabIndex={-1}
                aria-label="Clear text"
                onMouseDown={e => { e.preventDefault(); handleClear(); }}
              >
                <img src={cancelFillIcon} alt="" />
              </button>
            )}

            {/* Custom scrollbar: track starts 8px below cancel button bottom (top: 26px) */}
            <div
              ref={scrollTrackRef}
              className="bt-input-text-area__scrollbar-track"
              style={{ display: showScrollbar ? 'block' : 'none' }}
            >
              <div
                className="bt-input-text-area__scrollbar-thumb"
                style={{ height: thumbHeight, top: thumbTop }}
                onMouseDown={handleThumbMousedown}
              />
            </div>

          </div>
        </div>

        {/* Footer */}
        {showFooter && (
          <div className="bt-input-text-area__footer">
            {activeError
              ? <span className="bt-input-text-area__error">{activeError}</span>
              : helperText
              ? <span className="bt-input-text-area__helper">{helperText}</span>
              : <span />}
            {maxLength !== undefined && (
              <span className="bt-input-text-area__char-count">
                {(value ?? '').length}/{maxLength}
              </span>
            )}
          </div>
        )}

      </div>
    );
  },
);

BTInputTextArea.displayName = 'BTInputTextArea';

export interface BTInputTextAreaHandle {
  validate: () => boolean;
}

export interface BTInputTextAreaProps {
  /** Controlled value. */
  value?: string;
  label?: string;
  placeholder?: string;
  required?: boolean;
  disabled?: boolean;
  errorText?: string;
  helperText?: string;
  /** Hard caps input length. When set, a character counter is shown. */
  maxLength?: number;
  /** Kept for API compatibility — not used in rendering (auto-grow handles height). */
  rows?: number;
  /** Called on every keystroke. */
  onChange?: (value: string) => void;
  /** Called when the clear button is clicked. */
  onClear?: () => void;
  /** Return an error string to fail validation, null to pass. */
  validator?: (value: string) => string | null;
  className?: string;
}

/* Clear-button slide-in / slide-out animation — shared canonical definition */
