/*
 * BTInputTime — masked time text-input field.
 * Figma node 555-2975.
 *
 * Layout follows BTInputDate exactly — position:relative on the field div,
 * label is position:absolute inside it. No popover panel.
 *
 * Visual structure (flex-row, height 48px — same as BTInputDate):
 * ┌── field (position:relative) ────────────────────────────────┐
 * │  [🕐 16px] │  label (absolute, resting↔floating) │  input  │ [×?] │
 * └──────────────────────────────────────────────────────────────┘
 */

/* ── Outer wrapper ───────────────────────────────────────────── */
.bt-input-time__wrapper {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  font-family: var(--typography-font-family-sans);
  width: 100%;
}

/* ── Field row ───────────────────────────────────────────────── */
.bt-input-time {
  position: relative;
  display: flex;
  align-items: center;
  height: 48px;
  box-sizing: border-box;
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  background: var(--bg-primary);
  padding: 0 8px;
  gap: var(--space-sm);
  cursor: text;
  user-select: none;
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-time--label-floating {
  padding-top: 8px;
  padding-bottom: 8px;
}

/* States */
.bt-input-time--focused  { border-color: var(--color-brand-primary); }
.bt-input-time--error    { border-color: var(--text-error); }
.bt-input-time--disabled {
  background: var(--bg-subtle);
  cursor: not-allowed;
  pointer-events: none;
}

/* ── Clock icon ──────────────────────────────────────────────── */
.bt-input-time__icon {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  color: var(--text-secondary);
}

.bt-input-time__icon img,
.bt-input-time__icon svg {
  width: 16px;
  height: 16px;
  display: block;
}

.bt-input-time--focused  .bt-input-time__icon { color: var(--color-brand-primary); }
.bt-input-time--error    .bt-input-time__icon { color: var(--text-error); }
.bt-input-time--disabled .bt-input-time__icon { color: var(--text-disabled); }

/* ── Floating label ──────────────────────────────────────────── */
/*
 * left: 32px = 8px(pad) + 16px(icon) + 8px(gap)
 */
.bt-input-time__label {
  position: absolute;
  pointer-events: none;
  inset-inline-start: var(--space-2xl);
  top: 50%;
  transform: translateY(-50%);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: calc(100% - 56px);
  transition: top        150ms cubic-bezier(0.4, 0, 0.2, 1),
              transform  150ms cubic-bezier(0.4, 0, 0.2, 1),
              font-size  150ms cubic-bezier(0.4, 0, 0.2, 1),
              color      150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-time--label-floating .bt-input-time__label {
  top: var(--space-sm);
  transform: none;
  font-size: var(--typography-font-size-xs);
}

.bt-input-time--focused  .bt-input-time__label { color: var(--color-brand-primary); }
.bt-input-time--error    .bt-input-time__label { color: var(--text-error); }
.bt-input-time--disabled .bt-input-time__label { color: var(--text-disabled); }

.bt-input-time__label-required {
  color: var(--text-error);
  margin-inline-start: var(--space-2xs);
}

/* ── Native <input> ──────────────────────────────────────────── */
.bt-input-time__input {
  flex: 1;
  height: 100%;
  min-width: 0;
  border: none;
  outline: none;
  background: transparent;
  font-family: inherit;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  caret-color: var(--color-brand-primary);
  padding: 0;
  transition: padding-top 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-time--label-floating .bt-input-time__input {
  padding-top: 14px;
  align-self: flex-start;
}

.bt-input-time__input::placeholder {
  color: var(--text-secondary);
  font-weight: 500;
}

.bt-input-time--disabled .bt-input-time__input {
  color: var(--text-disabled);
  cursor: not-allowed;
}

/* ── AM/PM toggle button ─────────────────────────────────────── */
.bt-input-time__ampm {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  font-size: var(--typography-font-size-xs);
  font-weight: 600;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  background: var(--bg-subtle);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  padding: 2px 6px;
  cursor: pointer;
  user-select: none;
  transition: color 150ms, background 150ms, border-color 150ms;
}

.bt-input-time--focused .bt-input-time__ampm {
  color: var(--color-brand-primary);
  border-color: var(--color-brand-primary);
}

.bt-input-time--disabled .bt-input-time__ampm {
  color: var(--text-disabled);
  cursor: not-allowed;
}

/* ── Clear (×) button ────────────────────────────────────────── */
.bt-input-time__clear {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  width: 16px;
  height: 16px;
  color: var(--icon-primary);
}

.bt-input-time__clear img,
.bt-input-time__clear svg {
  width: 16px;
  height: 16px;
  display: block;
}

/* ── Helper / error text ─────────────────────────────────────── */
.bt-input-time__helper {
  display: flex;
  gap: var(--space-sm);
  padding: 0 8px;
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-input-time__helper-text        { flex: 1; color: var(--text-secondary); }
.bt-input-time__helper-text--error { color: var(--text-error); }

/* ── Small variant ───────────────────────────────────────────── */
.bt-input-time--small {
  height: auto;
  padding-top: 12px;
  padding-bottom: 12px;
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1),
              padding     150ms cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-input-time--small.bt-input-time--label-floating {
  padding-top: 4px;
  padding-bottom: 4px;
}

.bt-input-time--small.bt-input-time--label-floating .bt-input-time__label {
  top: var(--space-xs);
}

.bt-input-time--small .bt-input-time__input {
  height: auto;
  font-size: var(--typography-font-size-xs);
}

.bt-input-time--small.bt-input-time--label-floating .bt-input-time__input {
  padding-top: 16px;
  align-self: flex-start;
}

/**
 * BTInputTime — section-based masked time input (React).
 * Figma node 555-2975.
 *
 * Clicking a segment (hours / minutes / seconds / AM-PM) highlights it.
 * Typing digits fills the active segment and auto-advances to the next.
 * Backspace clears the current segment then retreats to the previous one.
 * No popup — user edits directly in the field.
 *
 * Usage — HH:mm (default):
 * ```tsx
 * <BTInputTime label="Time" value={time} onChange={setTime} />
 * ```
 * Usage — with seconds:
 * ```tsx
 * <BTInputTime label="Duration" format="HH:mm:ss" value={dur} onChange={setDur} />
 * ```
 * Usage — 12-hour (toggle AM/PM with A / P keys):
 * ```tsx
 * <BTInputTime label="Meeting" format="hh:mm a" value={t} onChange={setT} />
 * ```
 * Usage — with validation:
 * ```tsx
 * const ref = React.useRef<BTInputTimeHandle>(null);
 * <BTInputTime label="Start time" ref={ref}
 *              validator={(v) => v ? null : 'Required'} />
 * ```
 */
import * as React from 'react';
import './BTInputTime.css';
import type { BTInputTimeFormat, BTInputTimeHandle, BTInputTimeProps } from './BTInputTime.types';
import { BTInputAnimatedLabel } from '../internal/BTInputAnimatedLabel';
import scheduleIcon from './icons/schedule.svg';
import cancelIcon from './icons/cancel.svg';

const cn = (...parts: Array<string | false | null | undefined>): string =>
  parts.filter(Boolean).join(' ');

// ── Section type ─────────────────────────────────────────────────────────────

type Section = 'hours' | 'minutes' | 'seconds' | 'ampm';

function getSections(format: BTInputTimeFormat): Section[] {
  if (format === 'HH:mm:ss') return ['hours', 'minutes', 'seconds'];
  if (format === 'hh:mm a')  return ['hours', 'minutes', 'ampm'];
  return ['hours', 'minutes'];
}

// Character range [start, end] in the display string for each section.
// hh:mm a layout: "HH:MM AM" → hours[0,2] minutes[3,5] ampm[6,8]
// HH:mm:ss layout: "HH:MM:SS" → hours[0,2] minutes[3,5] seconds[6,8]
function sectionRange(section: Section): [number, number] {
  switch (section) {
    case 'hours':   return [0, 2];
    case 'minutes': return [3, 5];
    case 'seconds': return [6, 8];
    case 'ampm':    return [6, 8];
  }
}

function sectionAtPos(pos: number, format: BTInputTimeFormat): Section {
  if (pos <= 2) return 'hours';
  if (format === 'HH:mm:ss' && pos >= 6) return 'seconds';
  if (format === 'hh:mm a'  && pos >= 6) return 'ampm';
  return 'minutes';
}

function maxForSection(section: Section, format: BTInputTimeFormat): number {
  if (section === 'hours') return format === 'hh:mm a' ? 12 : 23;
  return 59;
}

function minForSection(section: Section, format: BTInputTimeFormat): number {
  return section === 'hours' && format === 'hh:mm a' ? 1 : 0;
}

function clampSection(value: string, section: Section, format: BTInputTimeFormat): string {
  const n = parseInt(value, 10);
  if (isNaN(n)) return '00';
  return String(Math.min(Math.max(n, minForSection(section, format)), maxForSection(section, format))).padStart(2, '0');
}

// While blurred with a value: show committed value.
// While focused or blurred+empty: show MUI-style format letters.
//   empty   → full placeholder ('HH', 'mm', 'ss')
//   partial → digit + remaining placeholder char (e.g. '1H', '4m')
//   full    → the value itself
function segDisplay(val: string, placeholder: string): string {
  if (!val) return placeholder;
  if (val.length === 1) return val + placeholder[1];
  return val;
}

// ── Component ────────────────────────────────────────────────────────────────

export const BTInputTime = React.forwardRef<BTInputTimeHandle, BTInputTimeProps>(
  function BTInputTime(
    {
      value,
      label,
      format = 'HH:mm',
      size = 'default',
      disabled = false,
      readOnly = false,
      required = false,
      errorText,
      helperText,
      id,
      onChange,
      onClear,
      validator,
      className,
    },
    ref,
  ) {
    const uid     = React.useId();
    const fieldId = id ?? `bt-input-time-${uid}`;

    const inputRef = React.useRef<HTMLInputElement>(null);

    const [isFocused,     setIsFocused]     = React.useState(false);
    const [activeSection, setActiveSection] = React.useState<Section | null>(null);
    const [sectionBuffer, setSectionBuffer] = React.useState('');
    const [hoursVal,      setHoursVal]      = React.useState('');
    const [minutesVal,    setMinutesVal]    = React.useState('');
    const [secondsVal,    setSecondsVal]    = React.useState('');
    const [amPmVal,       setAmPmVal]       = React.useState<'AM' | 'PM'>('AM');
    const [errorInternal, setErrorInternal] = React.useState<string | null>(null);

    // Use refs for values that keyDown handler reads to avoid stale closures
    const hoursRef        = React.useRef(hoursVal);
    const minutesRef      = React.useRef(minutesVal);
    const secondsRef      = React.useRef(secondsVal);
    const amPmRef         = React.useRef(amPmVal);
    const sectionBuffRef  = React.useRef(sectionBuffer);
    const activeSectionRef = React.useRef(activeSection);

    React.useEffect(() => { hoursRef.current        = hoursVal;      }, [hoursVal]);
    React.useEffect(() => { minutesRef.current       = minutesVal;    }, [minutesVal]);
    React.useEffect(() => { secondsRef.current       = secondsVal;    }, [secondsVal]);
    React.useEffect(() => { amPmRef.current          = amPmVal;       }, [amPmVal]);
    React.useEffect(() => { sectionBuffRef.current   = sectionBuffer; }, [sectionBuffer]);
    React.useEffect(() => { activeSectionRef.current = activeSection; }, [activeSection]);

    // ── Derived ───────────────────────────────────────────────────

    const activeError = errorText ?? errorInternal ?? null;
    const hasError    = !!activeError;
    const hasValue    = !!value;
    // Label always floats — format hint is always visible
    const showClear   = isFocused && hasValue && !disabled && !readOnly;

    // ── Display string ────────────────────────────────────────────

    const displayStr = React.useMemo(() => {
      if (!isFocused && value) return value;

      const hPh = format === 'hh:mm a' ? 'hh' : 'HH';
      const h   = segDisplay(hoursVal,   hPh);
      const m   = segDisplay(minutesVal, 'mm');

      if (format === 'HH:mm:ss') {
        return `${h}:${m}:${segDisplay(secondsVal, 'ss')}`;
      }
      if (format === 'hh:mm a') {
        return `${h}:${m} ${amPmVal}`;
      }
      return `${h}:${m}`;
    }, [isFocused, value, format, hoursVal, minutesVal, secondsVal, amPmVal]);

    // ── Section highlight ─────────────────────────────────────────

    const highlightSection = React.useCallback((section: Section | null) => {
      if (!section || !inputRef.current) return;
      const [start, end] = sectionRange(section);
      // rAF ensures the input value update has flushed before we set selection
      requestAnimationFrame(() => {
        inputRef.current?.setSelectionRange(start, end);
      });
    }, []);

    // Re-apply highlight after displayStr changes (browser resets cursor on value update)
    React.useEffect(() => {
      if (isFocused && activeSection) {
        highlightSection(activeSection);
      }
    }, [displayStr, isFocused, activeSection, highlightSection]);

    // ── Parse value into sections ─────────────────────────────────

    function parseValue(v: string) {
      const parts = v.split(/[: ]/);
      setHoursVal((parts[0] ?? '').replace(/\D/g, '').slice(0, 2));
      setMinutesVal((parts[1] ?? '').replace(/\D/g, '').slice(0, 2));
      if (format === 'HH:mm:ss') {
        setSecondsVal((parts[2] ?? '').replace(/\D/g, '').slice(0, 2));
      }
      if (format === 'hh:mm a') {
        setAmPmVal(v.toUpperCase().includes('PM') ? 'PM' : 'AM');
      }
    }

    function clearSections() {
      setHoursVal('');
      setMinutesVal('');
      setSecondsVal('');
      setSectionBuffer('');
    }

    // ── Emit ─────────────────────────────────────────────────────

    function buildEmitValue(
      h: string, m: string, s: string, ap: string,
    ): string | null {
      const h2 = h.length === 2;
      const m2 = m.length === 2;
      const s2 = format !== 'HH:mm:ss' || s.length === 2;
      if (!h2 || !m2 || !s2) return null;

      const hC = clampSection(h, 'hours', format);
      const mC = clampSection(m, 'minutes', format);

      if (format === 'HH:mm:ss') {
        return `${hC}:${mC}:${clampSection(s, 'seconds', format)}`;
      }
      if (format === 'hh:mm a') {
        return `${hC}:${mC} ${ap}`;
      }
      return `${hC}:${mC}`;
    }

    function tryEmit(h: string, m: string, s: string, ap: string) {
      const built = buildEmitValue(h, m, s, ap);
      if (built !== null) {
        onChange?.(built);
        setErrorInternal(null);
      }
    }

    // ── Section state helpers (read from refs to avoid stale closures) ─

    function getSectionValue(section: Section): string {
      if (section === 'hours')   return hoursRef.current;
      if (section === 'minutes') return minutesRef.current;
      if (section === 'ampm')    return amPmRef.current;
      return secondsRef.current;
    }

    function setSectionValue(section: Section, val: string) {
      if (section === 'hours')   { setHoursVal(val);   hoursRef.current   = val; return; }
      if (section === 'minutes') { setMinutesVal(val); minutesRef.current = val; return; }
      if (section === 'ampm')    return; // AM/PM toggled only via A/P keys
      setSecondsVal(val); secondsRef.current = val;
    }

    // ── Focus / blur ──────────────────────────────────────────────

    function handleFocus() {
      if (disabled || readOnly) return;
      setIsFocused(true);
      if (value) {
        parseValue(value);
      } else {
        clearSections();
      }
      setActiveSection('hours');
      activeSectionRef.current = 'hours';
      highlightSection('hours');
    }

    function handleBlur() {
      setIsFocused(false);
      // Commit if all sections are filled
      const built = buildEmitValue(
        hoursRef.current, minutesRef.current, secondsRef.current, amPmRef.current,
      );
      if (built !== null && built !== value) {
        onChange?.(built);
      }
      clearSections();
      setActiveSection(null);
      activeSectionRef.current = null;

      // Validate on blur — use the newly committed value (built) if available,
      // falling back to the incoming prop value to avoid stale-closure read.
      if (validator) {
        const result = validator(built ?? value ?? null);
        setErrorInternal(result ?? null);
      }
    }

    // ── Click: snap selection to the clicked section ──────────────

    function handleClick() {
      if (!inputRef.current) return;
      const pos     = inputRef.current.selectionStart ?? 0;
      const section = sectionAtPos(pos, format);
      if (section !== activeSectionRef.current) {
        setSectionBuffer('');
        sectionBuffRef.current = '';
      }
      setActiveSection(section);
      activeSectionRef.current = section;
      highlightSection(section);
    }

    // ── Section navigation ────────────────────────────────────────

    function advanceSection(current: Section): Section | null {
      const list = getSections(format);
      const idx  = list.indexOf(current);
      if (idx >= 0 && idx < list.length - 1) return list[idx + 1] ?? null;
      return null;
    }

    function retreatSection(current: Section): Section | null {
      const list = getSections(format);
      const idx  = list.indexOf(current);
      if (idx > 0) return list[idx - 1] ?? null;
      return null;
    }

    // ── Keyboard ─────────────────────────────────────────────────

    function handleKeyDown(e: React.KeyboardEvent<HTMLInputElement>) {
      if (e.key === 'Tab')    return; // let Tab blur normally
      if (e.key === 'Escape') { inputRef.current?.blur(); return; }

      const section = activeSectionRef.current;
      if (!section) return;

      // AM/PM toggle via A / P keys (12h only)
      if (format === 'hh:mm a') {
        if (e.key === 'a' || e.key === 'A') {
          e.preventDefault();
          setAmPmVal('AM'); amPmRef.current = 'AM';
          tryEmit(hoursRef.current, minutesRef.current, secondsRef.current, 'AM');
          highlightSection(section);
          return;
        }
        if (e.key === 'p' || e.key === 'P') {
          e.preventDefault();
          setAmPmVal('PM'); amPmRef.current = 'PM';
          tryEmit(hoursRef.current, minutesRef.current, secondsRef.current, 'PM');
          highlightSection(section);
          return;
        }
      }

      // ArrowLeft / ArrowRight — navigate sections
      if (e.key === 'ArrowLeft') {
        e.preventDefault();
        const prev = retreatSection(section);
        if (prev) {
          setActiveSection(prev);
          activeSectionRef.current = prev;
          setSectionBuffer('');
          sectionBuffRef.current = '';
          highlightSection(prev);
        }
        return;
      }
      if (e.key === 'ArrowRight') {
        e.preventDefault();
        const next = advanceSection(section);
        if (next) {
          setActiveSection(next);
          activeSectionRef.current = next;
          setSectionBuffer('');
          sectionBuffRef.current = '';
          highlightSection(next);
        }
        return;
      }

      // ArrowUp / ArrowDown — increment / decrement
      if (e.key === 'ArrowUp' || e.key === 'ArrowDown') {
        e.preventDefault();
        if (section === 'ampm') {
          const toggled = amPmRef.current === 'AM' ? 'PM' : 'AM';
          setAmPmVal(toggled); amPmRef.current = toggled;
          tryEmit(hoursRef.current, minutesRef.current, secondsRef.current, toggled);
          highlightSection(section);
          return;
        }
        const curVal = getSectionValue(section);
        const curNum = curVal ? parseInt(curVal, 10) : (e.key === 'ArrowUp' ? minForSection(section, format) - 1 : maxForSection(section, format) + 1);
        const maxV   = maxForSection(section, format);
        const minV   = minForSection(section, format);
        const newNum = e.key === 'ArrowUp'
          ? (curNum >= maxV ? minV : curNum + 1)
          : (curNum <= minV ? maxV : curNum - 1);
        const newStr = clampSection(String(newNum), section, format);
        setSectionValue(section, newStr);
        const h = section === 'hours'   ? newStr : hoursRef.current;
        const m = section === 'minutes' ? newStr : minutesRef.current;
        const s = section === 'seconds' ? newStr : secondsRef.current;
        tryEmit(h, m, s, amPmRef.current);
        highlightSection(section);
        return;
      }

      // Backspace
      if (e.key === 'Backspace') {
        e.preventDefault();

        if (section === 'ampm') {
          // Backspace from AM/PM → retreat to minutes
          const prev = retreatSection(section);
          if (prev) {
            setActiveSection(prev);
            activeSectionRef.current = prev;
            setSectionBuffer('');
            sectionBuffRef.current = '';
            highlightSection(prev);
          }
          return;
        }

        const buf    = sectionBuffRef.current;
        const curVal = getSectionValue(section);

        if (buf) {
          // Mid-typing: pop last digit
          const newBuf = buf.slice(0, -1);
          setSectionBuffer(newBuf);
          sectionBuffRef.current = newBuf;
          setSectionValue(section, newBuf);
        } else if (curVal) {
          // Section has a committed value: clear it
          setSectionValue(section, '');
          if (value) onChange?.(null);
        } else {
          // Section already empty: retreat and clear previous
          const prev = retreatSection(section);
          if (prev) {
            setActiveSection(prev);
            activeSectionRef.current = prev;
            setSectionBuffer('');
            sectionBuffRef.current = '';
            setSectionValue(prev, '');
            if (value) onChange?.(null);
            highlightSection(prev);
          }
        }
        highlightSection(activeSectionRef.current);
        return;
      }

      // Digit — skip if AM/PM section active
      if (/^\d$/.test(e.key)) {
        if (section === 'ampm') { e.preventDefault(); return; }
        e.preventDefault();
        onDigit(e.key, section);
        return;
      }

      e.preventDefault(); // block all other keys
    }

    function onDigit(digit: string, section: Section) {
      if (section === 'ampm') return;

      const newBuf = sectionBuffRef.current + digit;
      setSectionBuffer(newBuf);
      sectionBuffRef.current = newBuf;
      setSectionValue(section, newBuf);

      const bufNum = parseInt(newBuf, 10);
      const maxV   = maxForSection(section, format);

      // Auto-advance when:
      // 1. Buffer has 2 digits (section complete)
      // 2. First digit makes any second digit exceed max
      const shouldAdvance =
        newBuf.length === 2 ||
        (newBuf.length === 1 && bufNum * 10 > maxV);

      if (shouldAdvance) {
        const clamped = clampSection(newBuf, section, format);
        setSectionValue(section, clamped);
        setSectionBuffer('');
        sectionBuffRef.current = '';

        const next = advanceSection(section);
        if (next) {
          setActiveSection(next);
          activeSectionRef.current = next;
        } else {
          // Last digit-section complete — emit
          const h = section === 'hours'   ? clamped : hoursRef.current;
          const m = section === 'minutes' ? clamped : minutesRef.current;
          const s = section === 'seconds' ? clamped : secondsRef.current;
          tryEmit(h, m, s, amPmRef.current);
          activeSectionRef.current = section;
        }
      }

      highlightSection(activeSectionRef.current);
    }

    // ── Paste ─────────────────────────────────────────────────────

    function handlePaste(e: React.ClipboardEvent<HTMLInputElement>) {
      e.preventDefault();
      const digits = (e.clipboardData.getData('text') ?? '').replace(/\D/g, '');
      const maxLen = format === 'HH:mm:ss' ? 6 : 4;
      const d = digits.slice(0, maxLen);

      const h = d.slice(0, 2); const m = d.slice(2, 4); const s = d.slice(4, 6);
      setHoursVal(h);   hoursRef.current   = h;
      setMinutesVal(m); minutesRef.current = m;
      if (format === 'HH:mm:ss') { setSecondsVal(s); secondsRef.current = s; }

      if (d.length >= maxLen) {
        tryEmit(h, m, s, amPmRef.current);
        const list = getSections(format);
        const last: Section = list[list.length - 1] ?? 'minutes';
        setActiveSection(last);
        activeSectionRef.current = last;
        highlightSection(last);
      } else {
        const next: Section = (!h || h.length < 2)
          ? 'hours'
          : (!m || m.length < 2)
            ? 'minutes'
            : (format === 'HH:mm:ss' ? 'seconds' : 'minutes');
        setActiveSection(next);
        activeSectionRef.current = next;
        highlightSection(next);
      }
    }

    // ── Clear ─────────────────────────────────────────────────────

    function handleClear(e: React.MouseEvent) {
      e.stopPropagation();
      setErrorInternal(null);
      clearSections();
      setAmPmVal('AM'); amPmRef.current = 'AM';
      onChange?.(null);
      onClear?.();
      // Re-activate hours so the field remains keyboard-operable after clearing
      setActiveSection('hours');
      activeSectionRef.current = 'hours';
      // Re-focus the input and highlight the hours segment
      requestAnimationFrame(() => {
        inputRef.current?.focus();
        highlightSection('hours');
      });
    }

    // ── Imperative handle ─────────────────────────────────────────

    React.useImperativeHandle(ref, () => ({
      validate() {
        if (!validator) return true;
        const result = validator(value ?? null);
        setErrorInternal(result ?? null);
        return result === null;
      },
    }), [validator, value]);

    // ── Render ────────────────────────────────────────────────────

    const fieldClass = cn(
      'bt-input-time',
      isFocused   && 'bt-input-time--focused',
      'bt-input-time--label-floating', // label ALWAYS floats — format hint (HH:mm) is always visible (mirrors Vue: labelFloating = computed(() => true))
      hasError    && 'bt-input-time--error',
      disabled    && 'bt-input-time--disabled',
      size === 'small' && 'bt-input-time--small',
      className,
    );

    return (
      <div className="bt-input-time__wrapper">
        <div className={fieldClass}>
          {/* Clock icon */}
          <span className="bt-input-time__icon" aria-hidden="true">
            <img src={scheduleIcon} alt="" width={16} height={16} />
          </span>

          {/* Floating label */}
          {label && (
            <BTInputAnimatedLabel
              label={label}
              required={required}
              className="bt-input-time__label"
              requiredClassName="bt-input-time__label-required"
            />
          )}

          {/* Section-based text input */}
          <input
            ref={inputRef}
            id={fieldId}
            type="text"
            className="bt-input-time__input"
            value={displayStr}
            disabled={disabled}
            readOnly /* always readOnly — keydown handles all input; aria-readonly reflects the readOnly prop */
            aria-invalid={hasError || undefined}
            aria-required={required || undefined}
            aria-readonly={readOnly}
            autoComplete="off"
            spellCheck={false}
            onChange={() => { /* no-op: keydown handles all state */ }}
            onFocus={handleFocus}
            onBlur={handleBlur}
            onClick={handleClick}
            onKeyDown={handleKeyDown}
            onPaste={handlePaste}
          />

          {/* Clear (×) button */}
          {showClear && (
            <button
              type="button"
              className="bt-input-time__clear"
              aria-label="Clear time"
              onMouseDown={e => { e.preventDefault(); e.stopPropagation(); }}
              onClick={handleClear}
            >
              <img src={cancelIcon} alt="" width={16} height={16} />
            </button>
          )}
        </div>

        {/* Helper / error text */}
        {(activeError || helperText) && (
          <div className="bt-input-time__helper">
            <span className={cn('bt-input-time__helper-text', hasError && 'bt-input-time__helper-text--error')}>
              {activeError || helperText}
            </span>
          </div>
        )}
      </div>
    );
  },
);

BTInputTime.displayName = 'BTInputTime';

/**
 * BTInputTime — masked time-input field (React).
 * Figma node 555-2975.
 *
 * @example
 * <BTInputTime label="Start time" value={time} onChange={setTime} />
 * <BTInputTime label="Duration" format="HH:mm:ss" value={dur} onChange={setDur} />
 * <BTInputTime label="Meeting" format="hh:mm a" value={t} onChange={setT} />
 */

export type BTInputTimeFormat = 'HH:mm' | 'HH:mm:ss' | 'hh:mm a';

export type BTInputTimeSize = 'default' | 'small';

export interface BTInputTimeProps {
  /** Current time value — string matching the active format.
   *  e.g. "17:58" for HH:mm, "17:58:30" for HH:mm:ss, "05:30 PM" for hh:mm a.
   *  Pass null to clear. */
  value?: string | null;

  /** Floating label text. */
  label?: string;

  /**
   * Display and input format.
   * - 'HH:mm'    → 24-hour, 4 digits (HHMM)
   * - 'HH:mm:ss' → 24-hour with seconds, 6 digits (HHMMSS)
   * - 'hh:mm a'  → 12-hour, 4 digits + AM/PM toggle
   * @default 'HH:mm'
   */
  format?: BTInputTimeFormat;

  /** Field height variant.
   * - default: 48 px fixed height
   * - small:   auto height with smaller padding
   * @default 'default'
   */
  size?: BTInputTimeSize;

  disabled?: boolean;
  readOnly?: boolean;
  required?: boolean;

  /** External error message — overrides internal validator error. */
  errorText?: string;

  /** Helper text shown below the field. */
  helperText?: string;

  /** Override the generated `id` used for label association. */
  id?: string;

  /** Called when time value changes (null when cleared or incomplete). */
  onChange?: (value: string | null) => void;

  /** Called when the clear (×) button is clicked. */
  onClear?: () => void;

  /** Validator function — returns error string or null if valid. */
  validator?: (value: string | null) => string | null;

  /** Additional CSS class names applied to the field row. */
  className?: string;
}

export interface BTInputTimeHandle {
  /** Runs the validator and shows an error message if invalid. Returns true if valid. */
  validate: () => boolean;
}

export { BTInputTime } from './BTInputTime';
export type {
  BTInputTimeFormat,
  BTInputTimeHandle,
  BTInputTimeProps,
  BTInputTimeSize,
} from './BTInputTime.types';

/*
 * BTInputWithLabel — text input with static label pill(s) on left, right, or both.
 *
 * Shared by Vue (BTInputWithLabel.vue) and React (BTInputWithLabel.tsx).
 *
 * Figma node 368-6832.
 *
 * Layout (flex-row, height 48 px):
 * ┌── field ──────────────────────────────────────────────────────────┐
 * │ [left-pill?] │  label (14 px resting → 12 px float)  [×?] │ [right?] │
 * │              │  input text (always 100 % of content area)  │          │
 * └───────────────────────────────────────────────────────────────────┘
 *
 * Height arithmetic (box-sizing: border-box everywhere):
 *   Field container: 48 px  →  inner: 46 px (1 px border each side)
 *   Content area (align-self: stretch, border-box): 46 px outer
 *     Resting:  no padding   →  inner 46 px; input height 46 px, text centred by browser
 *     Floating: pad 8/8      →  inner 30 px; input height 30 px, padding-top 16 px
 *       → label at outer-top + 8 px (in pad zone), input text at 8 + 16 = 24 px ✓
 *
 * Key rules:
 *   • `box-sizing: border-box` on content area is mandatory — without it, padding
 *     increases the outer height beyond 46 px and the field grows.
 *   • Input uses `height: 100%` so it always fills the content area's inner height.
 *   • Clear (×) is a SIBLING of the content area (not inside it) so it can use
 *     `align-self: center` independent of the content padding.
 */

/* ── Outer wrapper ─────────────────────────────────────────────── */
.bt-input-with-label__wrapper {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  font-family: var(--typography-font-family-sans);
  width: 100%;
}

/* ── Field container ───────────────────────────────────────────── */
.bt-input-with-label {
  display: flex;
  flex-direction: row;
  align-items: stretch;                    /* pills + content fill full height */
  height: 48px;
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  background: var(--bg-primary);
  box-sizing: border-box;
  padding: 0 8px;                          /* right/left spacing when no pill */
  overflow: hidden;                        /* clip pill corners + any stray overflow */
  transition: border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

/* Remove padding from the side that has a pill */
.bt-input-with-label--has-left  { padding-inline-start: 0; }
.bt-input-with-label--has-right { padding-inline-end: 0; }

/* State colours */
.bt-input-with-label--focused  { border-color: var(--color-brand-primary); }
.bt-input-with-label--error    { border-color: var(--text-error); }
.bt-input-with-label--disabled { background: var(--bg-subtle); cursor: not-allowed; }

/* ── Label pill ────────────────────────────────────────────────── */
/* align-self: stretch (inherited from container) fills full height automatically */
.bt-input-with-label__pill {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  padding: 8px;
  background: var(--bg-subtle);
  flex-shrink: 0;
}

/* Outer corners only — inner edge flush with field border */
.bt-input-with-label__pill--left  { border-radius: var(--radius-sm) 0 0 var(--radius-sm); }
.bt-input-with-label__pill--right { border-radius: 0 var(--radius-sm) var(--radius-sm) 0; }

.bt-input-with-label--disabled .bt-input-with-label__pill {
  background: var(--bg-subtler);
}

.bt-input-with-label__pill-text {
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  white-space: nowrap;
  user-select: none;
}

.bt-input-with-label--disabled .bt-input-with-label__pill-text {
  color: var(--text-disabled);
}

/* ── Content area ──────────────────────────────────────────────── */
/*
 * CRITICAL: box-sizing must be border-box.
 * Without it, padding-top/bottom when floating adds to the outer height
 * (content-box outer = stretch-height + padding), breaking the 48 px constraint.
 * With border-box, padding is INSIDE the stretch-given height (46 px), so
 * inner = 46 − 8 − 8 = 30 px, and the field stays at exactly 48 px.
 */
.bt-input-with-label__content {
  position: relative;
  flex: 1;
  min-width: 0;
  display: flex;
  align-items: center;
  box-sizing: border-box;                  /* ← mandatory, see note above */
  padding-inline-start: var(--space-xs);
  padding-inline-end: var(--space-xs);
  transition: padding-top  150ms cubic-bezier(0.4, 0, 0.2, 1),
              padding-bottom 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

/* When label is floating — add top/bottom breathing room */
.bt-input-with-label__content--floating {
  padding-top: 8px;
  padding-bottom: 8px;
}

/* ── Floating label ────────────────────────────────────────────── */
.bt-input-with-label__label {
  position: absolute;
  inset-inline-start: var(--space-xs);
  inset-inline-end: var(--space-xs);
  top: 50%;
  transform: translateY(-50%);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  color: var(--text-secondary);
  pointer-events: none;
  user-select: none;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  transition: top 150ms cubic-bezier(0.4, 0, 0.2, 1),
              transform 150ms cubic-bezier(0.4, 0, 0.2, 1),
              font-size 150ms cubic-bezier(0.4, 0, 0.2, 1),
              color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}

/*
 * Floating: label at top: 8 px from content area outer edge.
 * Content area padding-top is also 8 px → label sits in the padding zone.
 * Input text is at 8 px (pad) + 16 px (input pad-top) = 24 px from outer. ✓
 */
.bt-input-with-label__label--floating {
  top: var(--space-sm);
  transform: none;
  font-size: var(--typography-font-size-xs);
}

.bt-input-with-label--focused  .bt-input-with-label__label--floating { color: var(--color-brand-primary); }
.bt-input-with-label--error    .bt-input-with-label__label           { color: var(--text-error); }
.bt-input-with-label--disabled .bt-input-with-label__label           { color: var(--text-disabled); }

.bt-input-with-label__label-required {
  color: var(--text-error);
  margin-inline-start: var(--space-2xs);
}

/* ── Input field ───────────────────────────────────────────────── */
/*
 * height: 100% fills the content area's inner height.
 *   Resting:  inner = 46 px → input 46 px; browser centres single-line text. ✓
 *   Floating: inner = 30 px → input 30 px; padding-top 16 px → text at 8+16=24 px. ✓
 */
.bt-input-with-label__field {
  flex: 1;
  min-width: 0;
  border: none;
  outline: none;
  background: transparent;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  color: var(--text-primary);
  padding: 0;
  height: 100%;
}

.bt-input-with-label__field::placeholder {
  color: var(--text-secondary);
}

.bt-input-with-label--disabled .bt-input-with-label__field {
  cursor: not-allowed;
  color: var(--text-disabled);
}

/* When label is floating: shift input text below the 16 px floating label */
.bt-input-with-label__content--floating .bt-input-with-label__field {
  padding-top: 16px;
}

/* ── Clear (×) button ──────────────────────────────────────────── */
/*
 * Sibling of content area (NOT inside it) so it can use align-self: center
 * and stay vertically centred in the full 46 px field height regardless of
 * whether the label is floating.
 */
.bt-input-with-label__clear {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  align-self: center;                      /* stays centred even when content has padding */
  background: none;
  border: none;
  padding: 0;
  margin-inline-start: var(--space-xs);
  cursor: pointer;
  width: 16px;
  height: 16px;
  color: var(--icon-primary);
}

.bt-input-with-label__clear img,
.bt-input-with-label__clear svg {
  width: 16px;
  height: 16px;
  display: block;
}

/* ── Helper / error text ───────────────────────────────────────── */
.bt-input-with-label__helper {
  display: flex;
  gap: var(--space-sm);
  padding: 0 8px;
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
}

.bt-input-with-label__helper-text        { flex: 1; color: var(--text-secondary); }
.bt-input-with-label__helper-text--error { color: var(--text-error); }

.bt-input-with-label__counter {
  color: var(--text-secondary);
  flex-shrink: 0;
}

/*
 * BTInputWithLabel — text input with static label pill(s) attached on the
 * left, right, or both sides — all sharing one unified border.
 *
 * Extends BTInput's floating-label behaviour. The pill is a static text badge
 * (e.g. "kg", "IDR", "m²") — not a dropdown (use BTInputFieldUnit for that).
 *
 * Figma node 368-6832.
 *
 * Variants (driven by which label props are provided):
 *   - leftLabel only  → L Label
 *   - rightLabel only → R Label
 *   - both            → L R Label
 *   - neither         → plain input (identical to BTInput)
 *
 * Usage:
 *   <BTInputWithLabel leftLabel="kg" label="Weight" value={v} onChange={setV} />
 *   <BTInputWithLabel rightLabel="m²" label="Area" value={v} onChange={setV} />
 *   <BTInputWithLabel leftLabel="From" rightLabel="IDR" label="Amount" value={v} onChange={setV} />
 *   <BTInputWithLabel
 *     leftLabel="Rp" label="Amount" required
 *     validator={(v) => (!v || isNaN(Number(v)) || Number(v) <= 0) ? 'Enter a positive number.' : null}
 *     ref={fieldRef}
 *   />
 */
import './BTInputWithLabel.css';
import { forwardRef, useId, useImperativeHandle, useMemo, useRef, useState } from 'react';
import type { BTInputWithLabelHandle, BTInputWithLabelProps } from './BTInputWithLabel.types';
import cancelIcon from '../icons/cancel.svg';

export const BTInputWithLabel = forwardRef<BTInputWithLabelHandle, BTInputWithLabelProps>(
  function BTInputWithLabel(props, ref) {
    const {
      value = '',
      onChange,
      leftLabel,
      rightLabel,
      label,
      required = false,
      placeholder,
      disabled = false,
      readOnly = false,
      errorText,
      helperText,
      id,
      name,
      maxLength,
      showCharCount = false,
      validator,
      onClear,
      onFocus,
      onBlur,
    } = props;

    const [isFocused,     setIsFocused]     = useState(false);
    const [errorInternal, setErrorInternal] = useState<string | null>(null);

    const generatedId = useId();
    const fieldId     = id ?? `bt-input-wl-${generatedId}`;
    const inputRef    = useRef<HTMLInputElement>(null);

    const activeError = errorText ?? errorInternal ?? null;
    const hasError    = !!activeError;
    const isEmpty     = !value;

    const labelFloating = useMemo(
      () => !!label && (isFocused || !isEmpty),
      [label, isFocused, isEmpty],
    );

    const showClear = !isEmpty && isFocused && !disabled && !readOnly;

    // ── CSS classes ────────────────────────────────────────────────────────
    const fieldClass = [
      'bt-input-with-label',
      leftLabel  && 'bt-input-with-label--has-left',
      rightLabel && 'bt-input-with-label--has-right',
      isFocused  && 'bt-input-with-label--focused',
      hasError   && 'bt-input-with-label--error',
      disabled   && 'bt-input-with-label--disabled',
    ].filter(Boolean).join(' ');

    const contentClass = [
      'bt-input-with-label__content',
      labelFloating && 'bt-input-with-label__content--floating',
    ].filter(Boolean).join(' ');

    const labelClass = [
      'bt-input-with-label__label',
      labelFloating && 'bt-input-with-label__label--floating',
    ].filter(Boolean).join(' ');

    // ── Handlers ──────────────────────────────────────────────────────────
    function handleInput(e: React.ChangeEvent<HTMLInputElement>) {
      setErrorInternal(null);
      onChange?.(e.target.value);
    }

    function handleFocus(e: React.FocusEvent<HTMLInputElement>) {
      setIsFocused(true);
      onFocus?.(e);
    }

    function handleBlur(e: React.FocusEvent<HTMLInputElement>) {
      setIsFocused(false);
      onBlur?.(e);
    }

    function handleClear() {
      setErrorInternal(null);
      onChange?.('');
      onClear?.();
      inputRef.current?.focus();
    }

    // ── Validation ────────────────────────────────────────────────────────
    function validate(): boolean {
      if (!validator) return true;
      const result = validator(value);
      setErrorInternal(result ?? null);
      return result === null;
    }

    useImperativeHandle(ref, () => ({ validate }));

    // ── Render ────────────────────────────────────────────────────────────
    return (
      <div className="bt-input-with-label__wrapper">

        {/* Field container */}
        <div className={fieldClass}>

          {/* Left label pill */}
          {leftLabel && (
            <div
              className="bt-input-with-label__pill bt-input-with-label__pill--left"
              aria-hidden="true"
            >
              <span className="bt-input-with-label__pill-text">{leftLabel}</span>
            </div>
          )}

          {/* Content: floating label + input */}
          <div className={contentClass}>

            {/* Floating label */}
            {label && (
              <label htmlFor={fieldId} className={labelClass}>
                {label}
                {required && (
                  <span className="bt-input-with-label__label-required">*</span>
                )}
              </label>
            )}

            {/* Input */}
            <input
              ref={inputRef}
              id={fieldId}
              name={name}
              value={value}
              className="bt-input-with-label__field"
              placeholder={!label || labelFloating ? (placeholder ?? '') : ''}
              disabled={disabled}
              readOnly={readOnly}
              maxLength={maxLength}
              type="text"
              onChange={handleInput}
              onFocus={handleFocus}
              onBlur={handleBlur}
            />
          </div>

          {/* Clear (×) button — sibling of content so align-self: center works
              independently of the content area's padding state */}
          {showClear && (
            <button
              type="button"
              className="bt-input-with-label__clear"
              aria-label="Clear input"
              onPointerDown={(e) => { e.preventDefault(); handleClear(); }}
            >
              <img src={cancelIcon} alt="" />
            </button>
          )}

          {/* Right label pill */}
          {rightLabel && (
            <div
              className="bt-input-with-label__pill bt-input-with-label__pill--right"
              aria-hidden="true"
            >
              <span className="bt-input-with-label__pill-text">{rightLabel}</span>
            </div>
          )}

        </div>

        {/* Helper / error text */}
        {(activeError || helperText || (showCharCount && maxLength)) && (
          <div className="bt-input-with-label__helper">
            <span
              className={[
                'bt-input-with-label__helper-text',
                hasError && 'bt-input-with-label__helper-text--error',
              ].filter(Boolean).join(' ')}
            >
              {activeError || helperText}
            </span>
            {showCharCount && maxLength && (
              <span className="bt-input-with-label__counter">
                {(value || '').length}/{maxLength}
              </span>
            )}
          </div>
        )}

      </div>
    );
  },
);

BTInputWithLabel.displayName = 'BTInputWithLabel';

/**
 * Props for {@link BTInputWithLabel}.
 *
 * @example Left label (unit prefix like "kg", "IDR")
 * <BTInputWithLabel leftLabel="kg" label="Weight" value={value} onChange={setValue} />
 *
 * @example Right label
 * <BTInputWithLabel rightLabel="m²" label="Area" value={value} onChange={setValue} />
 *
 * @example Both sides
 * <BTInputWithLabel leftLabel="From" rightLabel="IDR" label="Amount" value={value} onChange={setValue} />
 */
export interface BTInputWithLabelProps {
  /** Current value. */
  value?: string;

  /** Called with the new string whenever the input changes. */
  onChange?: (value: string) => void;

  /**
   * Text shown inside the left label pill.
   * When omitted no left pill is rendered.
   */
  leftLabel?: string;

  /**
   * Text shown inside the right label pill.
   * When omitted no right pill is rendered.
   */
  rightLabel?: string;

  /**
   * Floating label inside the input — sits centred when empty/idle,
   * floats small (12 px) at the top on focus or when the field has a value.
   */
  label?: string;

  /** Appends " *" (red) to the floating label. @default false */
  required?: boolean;

  /** Hint text shown inside the input when empty and focused. */
  placeholder?: string;

  /** Disables all interaction and dims the field. @default false */
  disabled?: boolean;

  /** Makes the field read-only (shows value, blocks edits). @default false */
  readOnly?: boolean;

  /** Red border + validation text shown below the field. */
  errorText?: string;

  /** Text shown below the field when there is no error. */
  helperText?: string;

  /** HTML id forwarded to the underlying <input>. */
  id?: string;

  /** HTML name forwarded to the underlying <input>. */
  name?: string;

  /** Maximum character count; also used by showCharCount. */
  maxLength?: number;

  /** Show current / max character counter below the field. @default false */
  showCharCount?: boolean;

  /**
   * Custom validation function. Called by `validate()` — returns an error
   * string or null.
   */
  validator?: (value: string) => string | null;

  /** Called when the clear (×) button is clicked. */
  onClear?: () => void;

  /** Called on focus. */
  onFocus?: (e: React.FocusEvent<HTMLInputElement>) => void;

  /** Called on blur. */
  onBlur?: (e: React.FocusEvent<HTMLInputElement>) => void;
}

/** Imperative handle exposed via ref. */
export interface BTInputWithLabelHandle {
  /** Runs the validator and shows the error. Returns true if valid. */
  validate: () => boolean;
}

